class _FakeJsonHandler:
    def __init__(self, payload=None):
        raw = json.dumps(payload or {}).encode("utf-8")
        self.status = None
        self.headers = {"Content-Length": str(len(raw))}
        self.sent_headers = []
        self.body = bytearray()
        self.rfile = io.BytesIO(raw)
        self.wfile = self

    def send_response(self, status):
        self.status = status

    def send_header(self, name, value):
        self.sent_headers.append((name, value))

    def end_headers(self):
        pass

    def write(self, data):
        self.body.extend(data)

    def json_body(self):
        return json.loads(bytes(self.body).decode("utf-8"))


def _progress_log_rows(path):
    if not path.exists():
        return []
    return [json.loads(line) for line in path.read_text(encoding="utf-8").splitlines() if line.strip()]


def _assert_memory_advisory_receipt(payload):
    assert payload["memory_advisory"] == {
        "metadata_only": True,
        "advisory_context": True,
        "context_authority": "untrusted_advisory",
        "can_bypass_safety_gates": False,
        "required_gates": ["prompt_preflight", "approval", "sandbox_preview", "visual_qa", "rollback_recovery"],
    }


@pytest.fixture(autouse=True)
def _isolate_capy_progress_log(tmp_path, monkeypatch):
    monkeypatch.setenv("CAPY_PROGRESS_LOG", str(tmp_path / "capy-progress-events.jsonl"))


