    init_memory_tree()

    variants = [
        (
            "github-single-pr-json-suffixed-route-marker",
            "https://api.github.com/repos/o/r/pulls.json/42?token=x#frag",
        ),
        (
            "github-single-pr-encoded-slash-route-marker",
            "https://api.github.com/repos/o/r/pulls%2F42?token=x#frag",
        ),
        (
            "github-single-pr-joined-number-route-marker",
            "https://api.github.com/repos/o/r/pulls42?token=x#frag",
        ),
    ]
    receipts = [
        register_source_reference({
            "source_id": source_id,
            "title": "GitHub Single PR Suffixed Route Marker",
            "origin_uri": origin_uri,
        })
        for source_id, origin_uri in variants
    ]
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "text/plain; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def read(self, _limit=-1):
            return b"Summary: unsafe single PR route-marker lookalike text fallback."

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    result = run_source_refresh_jobs(limit=len(variants))
    jobs = list_source_refresh_jobs(limit=len(variants))
    serialized = json.dumps({"receipts": receipts, "result": result, "jobs": jobs}, sort_keys=True).lower()

    assert [receipt["origin_uri"] for receipt in receipts] == [
        f"capy-memory://{source_id}" for source_id, _origin_uri in variants
    ]
    assert {job["origin_uri"] for job in jobs["jobs"]} == {
        f"capy-memory://{source_id}" for source_id, _origin_uri in variants
    }
    assert calls == []
    assert result["processed"] == len(variants)
    assert [job["status"] for job in result["jobs"]] == ["pending", "pending", "pending"]
    assert {job["error"] for job in result["jobs"]} <= {"refresh fetcher disabled", "refresh failed"}
    for source_id, _origin_uri in variants:
        assert not (root / "vault" / f"{source_id}.md").exists()
    assert "unsafe single pr route-marker lookalike text fallback" not in serialized
    assert "pulls.json" not in serialized
    assert "pulls%2f42" not in serialized
    assert "pulls42" not in serialized
    assert "token=x" not in serialized
    assert "frag" not in serialized


