def test_legacy_github_forks_uppercase_host_public_surfaces_fail_closed(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    init_memory_tree()
    source_id = "legacy-github-forks-uppercase-host"
    legacy_origin_uri = "https://API.GITHUB.COM/repos/capy/spaces/forks?access_token=***#raw-prompt"
    now = "2026-06-06T00:00:00+00:00"
    payload = {"source_id": source_id, "origin_uri": legacy_origin_uri}

    with sqlite3.connect(memory_tree_db_path()) as conn:
        conn.execute(
            """
            INSERT INTO sources (
                source_id, source_type, display_name, origin_uri, origin_kind,
                freshness_status, last_checked_at, created_at, updated_at
            )
            VALUES (?, 'github', 'Legacy GitHub Forks', ?, 'auto_fetch', 'stale', ?, ?, ?)
            """,
            (source_id, legacy_origin_uri, now, now, now),
        )
        conn.execute(
            """
            INSERT INTO jobs (job_id, kind, dedupe_key, payload_json, status, attempts, created_at, updated_at)
            VALUES ('cmt-job-legacy-github-forks-uppercase-host', 'source.refresh', ?, ?, 'pending', 0, ?, ?)
            """,
            (source_id, json.dumps(payload, sort_keys=True, separators=(",", ":")), now, now),
        )

    catalog = capy_memory.source_catalog(limit=5)
    jobs = list_source_refresh_jobs(limit=5)
    catalog_source = next(
        source
        for connector in catalog["connectors"]
        for source in connector["sources"]
        if source["source_id"] == source_id
    )
    queued_job = next(job for job in jobs["jobs"] if job["source_id"] == source_id)
    serialized = json.dumps({"catalog": catalog, "jobs": jobs}, sort_keys=True).lower()

    assert catalog_source["origin_uri"] == "capy-memory://legacy-github-forks-uppercase-host"
    assert queued_job["origin_uri"] == "capy-memory://legacy-github-forks-uppercase-host"
    assert "api.github.com/repos/capy/spaces/forks" not in serialized
    assert "access_token" not in serialized
    assert "raw-prompt" not in serialized


