@pytest.mark.parametrize(("source_suffix", "raw_route"), [
    ("schemeless", "api.github.com/repos/capy/spaces/actions/artifacts/201"),
    ("schemeless-port", "api.github.com:443/repos/capy/spaces/actions/artifacts/201"),
    ("schemeless-lookalike", "api.github.com.evil.test/repos/capy/spaces/actions/artifacts/201"),
    (
        "https-lookalike-authority",
        "https://api.github.com.evil.test/repos/capy/spaces/actions/artifacts/201?access_token=SECRET#raw-prompt",
    ),
])
def test_run_source_refresh_jobs_default_fetcher_rejects_github_single_artifact_route_hint(
    tmp_path,
    monkeypatch,
    source_suffix,
    raw_route,
):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    source_id = f"github-single-artifact-{source_suffix}-source-refresh"
    receipt = register_source_reference({
        "source_id": source_id,
        "title": "GitHub Single Artifact Schemeless Source Refresh",
        "origin_uri": raw_route,
    })
    jobs = list_source_refresh_jobs(limit=5)
    catalog = capy_memory.source_catalog(limit=5)
    with sqlite3.connect(memory_tree_db_path()) as conn:
        payload = json.loads(conn.execute(
            "SELECT payload_json FROM jobs WHERE job_id = ?",
            (receipt["job_id"],),
        ).fetchone()[0])
    catalog_source = next(
        source
        for connector in catalog["connectors"]
        for source in connector["sources"]
        if source["source_id"] == source_id
    )
    registration_public = json.dumps({
        "receipt": receipt,
        "catalog": catalog,
        "jobs": jobs,
        "payload": payload,
    }, sort_keys=True).lower()

    assert receipt["origin_uri"] == f"capy-memory://{source_id}"
    assert catalog_source["origin_uri"] == f"capy-memory://{source_id}"
    assert jobs["jobs"][0]["origin_uri"] == f"capy-memory://{source_id}"
    assert payload["origin_uri"] == f"capy-memory://{source_id}"
    assert "fetch_origin_uri" not in payload
    for unsafe in (
        "api.github.com.evil.test",
        "api.github.com/repos/capy/spaces/actions/artifacts/201",
        "api.github.com:443/repos/capy/spaces/actions/artifacts/201",
        "api.github.com.evil.test/repos/capy/spaces/actions/artifacts/201",
        "access_token",
        "secret",
        "raw-prompt",
    ):
        assert unsafe not in registration_public

    calls = []

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout})
        raise AssertionError("unsafe GitHub artifact route hint must not be fetched")

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    result = run_source_refresh_jobs(limit=1)
    after_jobs = list_source_refresh_jobs(limit=5)
    serialized = json.dumps({"result": result, "jobs": after_jobs}, sort_keys=True).lower()
    assert calls == []
    for unsafe in (
        "api.github.com.evil.test",
        "api.github.com/repos/capy/spaces/actions/artifacts/201",
        "api.github.com:443/repos/capy/spaces/actions/artifacts/201",
        "api.github.com.evil.test/repos/capy/spaces/actions/artifacts/201",
        "access_token",
        "secret",
        "raw-prompt",
    ):
        assert unsafe not in serialized
    assert f"capy-memory://{source_id}" in serialized


def test_github_single_artifact_route_helpers_reject_unsafe_lookalikes():
    canonical_origin = "https://api.github.com/repos/capy/spaces/actions/artifacts/201"
    hostile_origin = "https://ghp_SECRET_VALUE_DO_NOT_LEAK@api.github.com/repos/capy/spaces/actions/artifacts/201?access_token=***#raw-prompt"
    assert capy_memory._github_single_artifact_safe_origin(hostile_origin) == canonical_origin
    assert capy_memory._github_single_artifact_public_origin(canonical_origin) == "github actions artifact capy/spaces 201"
    for unsafe_origin in (
        "https://api.github.com:443/repos/capy/spaces/actions/artifacts/201",
        "https://api.github.com.evil.test/repos/capy/spaces/actions/artifacts/201",
        "https://API.github.com/repos/capy/spaces/actions/artifacts/201",
        "http://api.github.com/repos/capy/spaces/actions/artifacts/201",
        "https://api.github.com/repos/capy/spaces/actions/artifacts/0",
        "https://api.github.com/repos/capy/spaces/actions/artifacts/201/zip",
        "https://api.github.com/repos/capy/spaces/actions/artifacts/201%2Fzip",
        "https://api.github.com/repos/capy/spaces/actions/artifacts/not-a-number",
    ):
        assert capy_memory._github_single_artifact_path_info(unsafe_origin) is None
        assert capy_memory._github_single_artifact_safe_origin(unsafe_origin) == ""
    assert capy_memory._github_single_artifact_route_path_hint_matches(
        "https://api.github.com.evil.test/repos/capy/spaces/actions/artifacts/201?access_token=SECRET#raw-prompt"
    )


