def test_queue_due_source_refresh_jobs_preserves_github_check_run_annotations_fetch_origin_for_second_run(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    receipt = register_source_reference({
        "source_id": "github-check-run-annotations-due-refresh",
        "title": "GitHub Check Run Annotations Due Refresh",
        "origin_uri": "https://api.github.com/repos/capy/spaces/check-runs/701/annotations?access_token=***#raw-prompt",
        "refresh_interval_seconds": 60,
    })
    public_origin = "github check run annotations capy/spaces check run 701"
    canonical_fetch_origin = "https://api.github.com/repos/capy/spaces/check-runs/701/annotations"
    github_annotations_body = json.dumps([{
        "annotation_level": "warning",
        "severity": "medium",
        "message": "SECRET_VALUE_DO_NOT_LEAK raw annotation message",
        "path": "src/private.py",
    }]).encode("utf-8")
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def read(self, _limit=-1):
            return github_annotations_body

    def fake_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.headers.get("Accept")})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_open)

    first_result = run_source_refresh_jobs(limit=1)
    assert first_result["processed"] == 1
    assert first_result["jobs"][0]["status"] == "completed"
    assert calls == [{"url": canonical_fetch_origin, "timeout": 8, "accept": "application/json"}]

    due_result = queue_due_source_refresh_jobs(limit=1, now="2999-01-01T00:00:00+00:00")
    assert due_result["queued"] == 1
    assert due_result["jobs"][0]["origin_uri"] == public_origin
    with capy_memory._connect() as conn:
        payload_json = conn.execute(
            "SELECT payload_json FROM jobs WHERE job_id = ?",
            (receipt["job_id"],),
        ).fetchone()[0]
    requeued_payload = json.loads(payload_json)
    assert requeued_payload["origin_uri"] == public_origin
    assert requeued_payload["fetch_origin_uri"] == canonical_fetch_origin
    assert requeued_payload["source_refresh_kind"] == "github_check_run_annotations"

    calls.clear()
    second_result = run_source_refresh_jobs(limit=1, queue_due=False)
    persisted = (root / "vault" / "github-check-run-annotations-due-refresh.md").read_text(encoding="utf-8").lower()
    catalog = source_catalog(limit=5)
    search = search_memory("GitHub check run annotations", limit=5)
    public_serialized = json.dumps({
        "first_result": first_result,
        "due_result": due_result,
        "second_result": second_result,
        "catalog": catalog,
        "search": search,
    }, sort_keys=True).lower()

    assert second_result["processed"] == 1
    assert second_result["jobs"][0]["status"] == "completed"
    assert calls == [{"url": canonical_fetch_origin, "timeout": 8, "accept": "application/json"}]
    assert catalog["connectors"][0]["sources"][0]["origin_uri"] == public_origin
    assert search["results"][0]["origin_uri"] == public_origin
    assert "origin_uri: github check run annotations capy/spaces check run 701" in persisted
    assert "github check run annotations for capy/spaces check run 701" in persisted
    assert "https://api.github.com" not in public_serialized
    assert "api.github.com" not in public_serialized
    assert canonical_fetch_origin.lower() not in public_serialized
    assert canonical_fetch_origin.lower() not in persisted
    assert "secret_value_do_not_leak" not in public_serialized
    assert "secret_value_do_not_leak" not in persisted
    assert "src/private.py" not in public_serialized
    assert "src/private.py" not in persisted


