def test_run_source_refresh_jobs_default_fetcher_rejects_github_check_run_annotations_route_abuse_before_fetch(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com,api.github.com.evil.invalid")
    init_memory_tree()
    abusive_origins = {
        "lookalike": "https://api.github.com.evil.invalid/repos/capy/spaces/check-runs/701/annotations",
        "userinfo": "https://user@api.github.com/repos/capy/spaces/check-runs/701/annotations",
        "explicit-port": "https://api.github.com:443/repos/capy/spaces/check-runs/701/annotations",
        "uppercase-authority": "https://API.GITHUB.COM/repos/capy/spaces/check-runs/701/annotations",
        "malformed-id": "https://api.github.com/repos/capy/spaces/check-runs/not-a-number/annotations",
        "extra-tail": "https://api.github.com/repos/capy/spaces/check-runs/701/annotations/extra",
        "encoded-tail": "https://api.github.com/repos/capy/spaces/check-runs/701/annotations%2Fextra",
    }
    for name, origin_uri in abusive_origins.items():
        register_source_reference({
            "source_id": f"github-check-run-annotations-{name}",
            "title": f"GitHub Check Run Annotations {name}",
            "origin_uri": origin_uri,
        })
    refresh_open_calls = 0

    def fake_open(*_args, **_kwargs):
        nonlocal refresh_open_calls
        refresh_open_calls += 1
        raise AssertionError("unsafe check-run annotations route should be rejected before fetch")

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_open)

    result = run_source_refresh_jobs(limit=len(abusive_origins))
    serialized = json.dumps(result, sort_keys=True).lower()

    assert result["processed"] == len(abusive_origins)
    assert [job["status"] for job in result["jobs"]] == ["pending"] * len(abusive_origins)
    assert {job["error"] for job in result["jobs"]} <= {"refresh failed", "refresh fetcher disabled"}
    assert refresh_open_calls == 0
    for name in abusive_origins:
        assert not (root / "vault" / f"github-check-run-annotations-{name}.md").exists()
    assert "safe-looking annotations summary" not in serialized
    assert "access_token" not in serialized
    assert "raw-prompt" not in serialized


