def test_queue_due_source_refresh_jobs_preserves_github_commit_pulls_fetch_origin(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    commit_sha = "0123456789abcdef0123456789abcdef01234567"
    clean_api_url = f"https://api.github.com/repos/capy/spaces/commits/{commit_sha}/pulls"
    public_origin = "github commit pull requests capy/spaces 0123456789ab"
    register_source_reference({
        "source_id": "github-commit-pulls-due-refresh",
        "title": "GitHub Commit Pulls Due Refresh",
        "origin_uri": f"https://api.github.com/repos/capy/spaces/commits/{commit_sha}/pulls?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt",
        "refresh_interval_seconds": 60,
    })
    github_commit_pulls_body = json.dumps([
        {"number": 123, "title": "Safe title", "state": "open", "draft": False, "user": {"login": "octocat"}},
    ]).encode("utf-8")
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __init__(self, url):
            self._url = url

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def geturl(self):
            return self._url

        def read(self, _limit=-1):
            return github_commit_pulls_body

    def fake_open(request, *, timeout):
        calls.append(request.full_url)
        return FakeResponse(request.full_url)

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_open)

    first = run_source_refresh_jobs(limit=1, queue_due=False)
    assert first["processed"] == 1
    assert first["jobs"][0]["status"] == "completed"
    assert calls == [clean_api_url]
    with sqlite3.connect(memory_tree_db_path()) as conn:
        conn.execute("UPDATE sources SET freshness_status = 'stale' WHERE source_id = ?", ("github-commit-pulls-due-refresh",))

    calls.clear()
    queued = queue_due_source_refresh_jobs(limit=1, now="2026-06-07T00:00:00+00:00")
    queued_serialized = json.dumps(queued, sort_keys=True).lower()
    public_jobs = list_source_refresh_jobs(limit=5)
    catalog = capy_memory.source_catalog(limit=5)
    with sqlite3.connect(memory_tree_db_path()) as conn:
        queued_payload = json.loads(conn.execute(
            "SELECT payload_json FROM jobs WHERE dedupe_key = 'github-commit-pulls-due-refresh'"
        ).fetchone()[0])
    second = run_source_refresh_jobs(limit=1, queue_due=False)
    search = search_memory("pull request #123", limit=5)
    public_serialized = json.dumps(
        {"queued": queued, "public_jobs": public_jobs, "catalog": catalog, "second": second, "search": search},
        sort_keys=True,
    ).lower()

    assert queued["queued"] == 1
    assert queued["jobs"][0]["origin_uri"] == public_origin
    assert public_jobs["jobs"][0]["origin_uri"] == public_origin
    assert queued_payload["origin_uri"] == public_origin
    assert queued_payload["fetch_origin_uri"] == clean_api_url
    assert calls == [clean_api_url]
    assert second["processed"] == 1
    assert second["jobs"][0]["status"] == "completed"
    assert search["results"][0]["origin_uri"] == public_origin
    assert clean_api_url not in queued_serialized
    assert clean_api_url not in public_serialized
    assert "api.github.com" not in public_serialized
    assert "secret_value_do_not_leak" not in public_serialized
    assert "access_token" not in public_serialized
    assert "raw-prompt" not in public_serialized


