def test_register_source_reference_rejects_github_commit_pulls_malformed_routes_before_fetch(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    commit_sha = "0123456789abcdef0123456789abcdef01234567"
    origins = [
        f"https://api.github.com/repos/capy/spaces/commits/{commit_sha[:-1]}/pulls?access_token=***#raw-prompt",
        f"https://api.github.com/repos/capy/spaces/commits/{commit_sha}/pulls/extra?access_token=***#raw-prompt",
        f"https://api.github.com/repos/capy/spaces/commits/{commit_sha}/pulls%2Fextra?access_token=***#raw-prompt",
        f"https://api.github.com/repos/capy/spaces/commits/{commit_sha}/pulls.json?access_token=***#raw-prompt",
        f"https://api.github.com/repos/capy/spaces/commits/{commit_sha}/pulls;param?access_token=***#raw-prompt",
        f"https://api.github.com/repos/capy/spaces/commits/{commit_sha}/pulls~?access_token=***#raw-prompt",
        f"https://api.github.com.evil.test/repos/capy/spaces/commits/{commit_sha}/pulls?access_token=***#raw-prompt",
        f"https://api.github.com:444/repos/capy/spaces/commits/{commit_sha}/pulls?access_token=***#raw-prompt",
        f"https://user:secret@api.github.com/repos/capy/spaces/commits/{commit_sha}/pulls?access_token=***#raw-prompt",
    ]
    for index, origin_uri in enumerate(origins):
        register_source_reference({
            "source_id": f"github-commit-pulls-malformed-{index}",
            "title": f"GitHub Commit Pulls Malformed {index}",
            "origin_uri": origin_uri,
        })
    calls = []

    def fail_if_called(*_args, **_kwargs):
        calls.append(True)
        raise AssertionError("malformed commit-pulls routes must fail before fetch")

    monkeypatch.setattr(capy_memory, "_refresh_open", fail_if_called)

    result = run_source_refresh_jobs(limit=len(origins))
    serialized = json.dumps({"result": result, "jobs": list_source_refresh_jobs(limit=20)}, sort_keys=True).lower()

    assert calls == []
    assert result["processed"] == len(origins)
    assert all(job["status"] == "pending" for job in result["jobs"])
    assert all(job["error"] == "refresh failed" for job in result["jobs"])
    assert not list((root / "vault").glob("github-commit-pulls-malformed-*.md"))
    assert "api.github.com" not in serialized
    assert "pulls.json" not in serialized
    assert "pulls;param" not in serialized
    assert "pulls~" not in serialized
    assert "api.github.com.evil" not in serialized
    assert "api.github.com:444" not in serialized
    assert "user:secret" not in serialized
    assert "secret_value_do_not_leak" not in serialized
    assert "access_token" not in serialized
    assert "raw-prompt" not in serialized


