def test_legacy_github_milestones_uppercase_host_public_surfaces_fail_closed(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    now = "2026-06-06T00:00:00+00:00"
    legacy_rows = [
        (
            "legacy-github-milestones-uppercase-host",
            "https://API.GITHUB.COM/repos/capy/spaces/milestones?access_token=***#raw-prompt",
        ),
        (
            "legacy-github-milestones-whitespace-uppercase-host",
            "  https://API.GITHUB.COM/repos/capy/spaces/milestones?access_token=***#raw-prompt  ",
        ),
    ]

    with sqlite3.connect(memory_tree_db_path()) as conn:
        for source_id, legacy_origin_uri in legacy_rows:
            conn.execute(
                """
                INSERT INTO sources (
                    source_id, source_type, display_name, origin_uri, origin_kind,
                    freshness_status, last_checked_at, created_at, updated_at
                )
                VALUES (?, 'github', 'Legacy GitHub Milestones', ?, 'auto_fetch', 'stale', ?, ?, ?)
                """,
                (source_id, legacy_origin_uri, now, now, now),
            )
            payload = {
                "source_id": source_id,
                "origin_uri": legacy_origin_uri,
                "raw_prompt": "raw prompt text SECRET_VALUE_DO_NOT_LEAK api_key <script>bad()</script>",
            }
            conn.execute(
                """
                INSERT INTO jobs (job_id, kind, dedupe_key, payload_json, status, attempts, created_at, updated_at)
                VALUES (?, 'source.refresh', ?, ?, 'pending', 0, ?, ?)
                """,
                (
                    f"cmt-job-{source_id}",
                    source_id,
                    json.dumps(payload, sort_keys=True, separators=(",", ":")),
                    now,
                    now,
                ),
            )

    calls = []

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout})
        raise AssertionError("legacy uppercase GitHub milestones host must not be fetched")

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    catalog = capy_memory.source_catalog(limit=5)
    queued = list_source_refresh_jobs(limit=5)
    result = run_source_refresh_jobs(limit=2, queue_due=False)
    queued_after = list_source_refresh_jobs(limit=5)
    search_milestones = search_memory("milestones", limit=5)
    catalog_sources = {
        source["source_id"]: source
        for connector in catalog["connectors"]
        for source in connector["sources"]
        if source["source_id"] in {source_id for source_id, _origin_uri in legacy_rows}
    }
    queued_jobs = {
        job["source_id"]: job
        for job in queued["jobs"]
        if job["source_id"] in {source_id for source_id, _origin_uri in legacy_rows}
    }
    queued_after_jobs = {
        job["source_id"]: job
        for job in queued_after["jobs"]
        if job["source_id"] in {source_id for source_id, _origin_uri in legacy_rows}
    }
    serialized = json.dumps(
        {
            "catalog": catalog,
            "queued": queued,
            "queued_after": queued_after,
            "result": result,
            "search_milestones": search_milestones,
        },
        sort_keys=True,
    ).lower()

    expected_origins = {source_id: f"capy-memory://{source_id}" for source_id, _origin_uri in legacy_rows}
    assert {source_id: source["origin_uri"] for source_id, source in catalog_sources.items()} == expected_origins
    assert {source_id: job["origin_uri"] for source_id, job in queued_jobs.items()} == expected_origins
    assert {source_id: job["origin_uri"] for source_id, job in queued_after_jobs.items()} == expected_origins
    assert calls == []
    assert result["processed"] == 2
    assert [job["status"] for job in result["jobs"]] == ["pending", "pending"]
    assert {job["error"] for job in result["jobs"]} <= {"refresh fetcher disabled", "refresh failed"}
    for source_id, _origin_uri in legacy_rows:
        assert not (root / "vault" / f"{source_id}.md").exists()
    for unsafe in (
        "api.github.com/repos",
        "access_token",
        "raw-prompt",
        "raw prompt text",
        "secret_value_do_not_leak",
        "api_key",
        "<script",
    ):
        assert unsafe not in serialized


