        "bypass_actors",
        "conditions",
        '"rules":',
        "_links",
        '"url":',
        "html_url",
        "api_key",
        "apiauth",
        "api_auth",
        "credential",
        "access_token",
        "ghp_",
        "token=",
        "?token",
        "raw-prompt",
