def test_run_source_refresh_jobs_does_not_persist_if_lease_lost_at_completion_handoff(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
