def test_spaces_memory_route_requires_space_id_and_returns_relevant_memory(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    init_memory_tree()
    record = canonicalize_space_manifest(_hostile_space_manifest())
    ingest_source(record)

    handled, status, missing = _route_get("/api/spaces/memory")
    assert handled is None
    assert status == 400
    assert "space_id" in missing["error"]

    handled, status, body = _route_get("/api/spaces/memory?spaceId=source-space&limit=5")

    assert handled is None
    assert status == 200
    assert body["space_id"] == "source-space"
    assert body["local_only"] is True
    assert body["metadata_only"] is True
    assert body["advisory_context"] is True
    assert body["context_authority"] == "untrusted_advisory"
    assert body["can_bypass_safety_gates"] is False
    assert body["required_gates"] == [
        "prompt_preflight",
        "approval",
        "sandbox_preview",
        "visual_qa",
        "rollback_recovery",
    ]
    assert [item["source_id"] for item in body["results"]] == [record["source_id"]]
    hit = body["results"][0]
    assert hit["metadata_only"] is True
    assert hit["advisory_context"] is True
    assert hit["context_authority"] == "untrusted_advisory"
    assert hit["can_bypass_safety_gates"] is False
    assert hit["required_gates"] == body["required_gates"]
    _assert_memory_advisory_receipt(body)
    assert body["memory_advisory"] == {
        "metadata_only": True,
        "advisory_context": True,
        "context_authority": "untrusted_advisory",
        "can_bypass_safety_gates": False,
        "required_gates": body["required_gates"],
    }
    prompt_preflight = body["prompt_preflight"]
    assert prompt_preflight["boundary"] == "memory_context"
    assert prompt_preflight["metadata_only"] is True
    assert prompt_preflight["prompt_text_stored"] is False
    assert prompt_preflight["source_text_stored"] is False
    assert prompt_preflight["status"] in {"pass", "required"}
    policy = body["autonomy_policy"]
    assert policy["action"] == "space.memory.read"
    assert policy["prompt_preflight_status"] == prompt_preflight["status"]
    assert policy["model_route_hint"] == "hint:summarize"
    assert policy["metadata_only"] is True
    assert policy["local_only"] is True
    assert policy["approval_required"] is True
    progress_event = body["progress_event"]
    assert progress_event["event_type"] == "tool.completed"
    assert progress_event["family"] == "tool"
    assert progress_event["run_id"] == "space.memory:source-space"
    assert progress_event["space_id"] == "source-space"
    if "redaction_status" in progress_event:
        assert progress_event["redaction_status"] == "metadata_only"
    output_compaction = body["output_compaction"]
    assert output_compaction["metadata_only"] is True
    assert output_compaction["tool"] == "capy-memory-relevant-memory"
    assert output_compaction["command"] == "space.memory.read"
    assert output_compaction["redaction_status"] == "metadata_only"
    output_text = output_compaction["text"].lower()
    assert "metadata_only: true" in output_text
    assert "advisory_context: true" in output_text
    assert "context_authority: untrusted_advisory" in output_text
    assert "can_bypass_safety_gates: false" in output_text
    assert f"prompt_preflight_status: {prompt_preflight['status']}" in output_text
    assert "progress_event_status: tool.completed" in output_text
    assert "progress_run_id: space.memory:source-space" in output_text
    assert "secretary cookie recipes" not in output_text
    assert "daily data dashboard" not in output_text
    assert "generated widget body" not in output_text
    assert "raw prompt" not in output_text
    serialized = json.dumps(body, sort_keys=True).lower()
    assert "secret_value_do_not_leak" not in serialized
    assert "<script" not in serialized
    assert "api_key" not in serialized
    assert "renderer" not in serialized
    assert "raw_prompt" not in serialized
    assert "generated widget body" not in serialized


