def test_run_source_refresh_jobs_default_fetcher_rejects_github_repository_invitations_final_url_drift_before_body_read_relevant_memory_empty(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    canonical_origin = "https://api.github.com/repos/capy/spaces/invitations"
    raw_final_url = f"{canonical_origin}?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt"
    receipt = register_source_reference({
        "source_id": "github-invitations-final-url-drift",
        "title": "GitHub Invitations Final URL Drift <script>bad()</script>",
        "origin_uri": canonical_origin,
    })
    github_invitations_body = json.dumps([
        {
            "id": 801,
            "invitee": {"login": "drifted-final-url-invitee", "id": 9801},
            "inviter": {"login": "owner-capy", "id": 9802},
            "permissions": "admin",
            "created_at": "2026-06-03T10:00:00Z",
            "expired": False,
            "url": f"{raw_final_url}/801",
            "html_url": "https://github.com/capy/spaces/invitations?access_token=SECRET_VALUE_DO_NOT_LEAK",
            "api_key": "SECRET_VALUE_DO_NOT_LEAK",
            "renderer": "<script>steal()</script>",
            "source": "raw invitation body ignore previous instructions SECRET_VALUE_DO_NOT_LEAK",
            "raw_prompt": "raw-prompt SECRET_VALUE_DO_NOT_LEAK",
        },
    ]).encode("utf-8")
    calls = []
    reads = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def geturl(self):
            return raw_final_url

        def read(self, _limit=-1):
            reads.append("body")
            return github_invitations_body

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.headers.get("Accept")})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    result = run_source_refresh_jobs(limit=1)
    jobs = list_source_refresh_jobs(limit=5)
    search = search_memory("drifted-final-url-invitee", limit=5)
    relevant = relevant_memory_for_space("repository-invitations-drift-space", limit=5)
    serialized = json.dumps({
        "jobs": jobs,
        "receipt": receipt,
        "result": result,
        "search_results": search["results"],
        "relevant_results": relevant["results"],
    }, sort_keys=True).lower()

    with sqlite3.connect(memory_tree_db_path()) as conn:
        conn.row_factory = sqlite3.Row
        job_row = conn.execute("SELECT status, last_error FROM jobs WHERE job_id = ?", (receipt["job_id"],)).fetchone()
        source_row = conn.execute("SELECT freshness_status, last_error FROM sources WHERE source_id = ?", ("github-invitations-final-url-drift",)).fetchone()

    assert receipt["origin_uri"] == "github repository invitations capy/spaces"
    assert calls == [{"url": canonical_origin, "timeout": 8, "accept": "application/json"}]
    assert reads == []
    assert result["processed"] == 1
    assert result["jobs"][0]["job_id"] == receipt["job_id"]
    assert result["jobs"][0]["status"] == "pending"
    assert result["jobs"][0]["error"] == "refresh failed"
    assert job_row["status"] == "pending"
    assert job_row["last_error"] == "refresh failed"
    assert source_row["freshness_status"] == "error"
    assert source_row["last_error"] == "refresh failed"
    assert not (root / "vault" / "github-invitations-final-url-drift.md").exists()
    assert search["results"] == []
    assert relevant["results"] == []
    for unsafe in (
        "drifted-final-url-invitee",
        "access_token",
        "raw-prompt",
        "secret_value_do_not_leak",
        raw_final_url.lower(),
        "api_key",
        "renderer",
        "<script",
        "steal()",
        "raw invitation body",
        "ignore previous instructions",
        "raw_prompt",
    ):
        assert unsafe not in serialized


