def test_run_source_refresh_jobs_default_fetcher_ingests_github_repository_single_invitation_metadata_only(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    receipt = register_source_reference({
        "source_id": "github-single-invitation-source-refresh",
        "title": "GitHub Repository Invitation Source Refresh <script>bad()</script>",
        "origin_uri": "https://api.github.com/repos/capy/spaces/invitations/701?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt",
    })
    github_invitation_body = json.dumps({
        "id": 701,
        "invitee": {"login": "new-capy", "id": 901, "html_url": "https://github.com/new-capy"},
        "inviter": {"login": "owner-capy", "id": 902, "url": "https://api.github.com/users/owner-capy"},
        "permissions": "write",
        "created_at": "2026-06-01T10:00:00Z",
        "expired": False,
        "url": "https://api.github.com/repos/capy/spaces/invitations/701",
        "html_url": "https://github.com/capy/spaces/invitations/701",
        "repository": {
            "id": 1001,
            "name": "spaces",
            "full_name": "capy/spaces",
            "private": True,
            "owner": {
                "login": "capy",
                "id": 1002,
                "url": "https://api.github.com/users/capy",
                "html_url": "https://github.com/capy",
                "avatar_url": "https://avatars.githubusercontent.com/u/1002?v=4",
            },
            "url": "https://api.github.com/repos/capy/spaces",
            "html_url": "https://github.com/capy/spaces",
            "archive_url": "https://api.github.com/repos/capy/spaces/{archive_format}{/ref}",
            "keys_url": "https://api.github.com/repos/capy/spaces/keys{/key_id}",
        },
    }).encode("utf-8")
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def read(self, _limit=-1):
            return github_invitation_body

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    result = run_source_refresh_jobs(limit=1)
    persisted = (root / "vault" / "github-single-invitation-source-refresh.md").read_text(encoding="utf-8").lower()
    search = search_memory("new-capy", limit=5)
    serialized = json.dumps({"receipt": receipt, "result": result, "search": search}, sort_keys=True).lower()

    assert calls == [{"url": "https://api.github.com/repos/capy/spaces/invitations/701", "timeout": 8}]
    assert result["processed"] == 1
    assert result["jobs"][0]["job_id"] == receipt["job_id"]
    assert result["jobs"][0]["status"] == "completed"
    preflight = result["jobs"][0]["prompt_preflight"]
    assert preflight["boundary"] == "auto_fetched_source"
    assert preflight["status"] == "pass"
    assert preflight["metadata_only"] is True
    assert preflight["raw_prompt_stored"] is False
    assert search["results"][0]["source_id"] == "github-single-invitation-source-refresh"
    assert "github repository invitation for capy/spaces" in persisted
    assert "invitation id: 701" in persisted
    assert "invitee: new-capy" in persisted
    assert "inviter: owner-capy" in persisted
    assert "permission: write" in persisted
    assert "expired: false" in persisted
    assert "created at: 2026-06-01t10:00:00z" in persisted
    for unsafe in (
        "secret_value_do_not_leak",
        "ignore previous instructions",
        "html_url",
        "api.github.com/users",
        "api.github.com/repos/capy/spaces",
        "github.com/capy",
        "github.com/new-capy",
        "api_key",
        "access_token",
        "?token",
        "raw-prompt",
        "renderer",
        "<script",
        "raw invitation body",
        "https://api.github.com/repos/capy/spaces/invitations/701",
    ):
        assert unsafe not in serialized
        assert unsafe not in persisted


