def test_github_security_advisories_hidden_fetch_origin_rejects_noncanonical_authorities(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    init_memory_tree()

    canonical_origin = "https://api.github.com/repos/capy/spaces/security-advisories"
    dirty_origin = f"{canonical_origin}?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt"
    assert capy_memory._github_security_advisories_safe_origin(canonical_origin) == canonical_origin
    assert capy_memory._github_security_advisories_safe_origin(dirty_origin) == canonical_origin

    unsafe_origins = {
        "userinfo": "https://user:pass@api.github.com/repos/capy/spaces/security-advisories?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt",
        "explicit-port": "https://api.github.com:444/repos/capy/spaces/security-advisories?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt",
        "explicit-default-port": "https://api.github.com:443/repos/capy/spaces/security-advisories?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt",
    }

    for suffix, unsafe_origin in unsafe_origins.items():
        source_id = f"github-security-advisories-{suffix}"
        assert capy_memory._github_security_advisories_safe_origin(unsafe_origin) == ""
        assert capy_memory._source_catalog_public_origin_uri(
            unsafe_origin,
            source_id=source_id,
        ) == f"capy-memory://{source_id}"

        receipt = register_source_reference({
            "source_id": source_id,
            "title": f"GitHub Security Advisories {suffix}",
            "origin_uri": unsafe_origin,
        })
        with sqlite3.connect(memory_tree_db_path()) as conn:
            stored_source_origin = conn.execute(
                "SELECT origin_uri FROM sources WHERE source_id = ?",
                (source_id,),
            ).fetchone()[0]
            queued_payload = json.loads(conn.execute(
                "SELECT payload_json FROM jobs WHERE job_id = ?",
                (receipt["job_id"],),
            ).fetchone()[0])

        public_origin = f"capy-memory://{source_id}"
        assert receipt["origin_uri"] == public_origin
        assert stored_source_origin == public_origin
        assert queued_payload["origin_uri"] == public_origin
        assert "fetch_origin_uri" not in queued_payload
        assert queued_payload.get("source_refresh_kind") != "github_security_advisories"

    serialized = json.dumps({
        "catalog": capy_memory.source_catalog(limit=10),
        "jobs": list_source_refresh_jobs(limit=10),
    }, sort_keys=True).lower()
    for unsafe in (
        "api.github.com/repos/capy/spaces/security-advisories",
        "user:pass",
        "api.github.com:444",
        "api.github.com:443",
        "access_token",
        "secret_value_do_not_leak",
        "raw-prompt",
        "raw prompt",
        "token",
    ):
        assert unsafe not in serialized


def test_source_catalog_neutralizes_unsafe_github_security_advisories_route_display_names(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    init_memory_tree()

    unsafe_userinfo_origin = "https://user:pass@api.github.com/repos/capy/spaces/security-advisories?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt"
    unsafe_port_origin = "https://api.github.com:444/repos/capy/spaces/security-advisories?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt"
    unsafe_userinfo_display = "https://user:pass@api.github.com/repos/capy/spaces/security-advisories"
    unsafe_port_display = "https://api.github.com:444/repos/capy/spaces/security-advisories"
    unsafe_schemeless_display = "api.github.com/repos/capy/spaces/security-advisories"
    unsafe_schemeless_port_display = "api.github.com:444/repos/capy/spaces/security-advisories"
    unsafe_embedded_url_display = f"Custom GHSA route {unsafe_userinfo_display} :444 context"
    unsafe_embedded_schemeless_display = f"Custom GHSA route {unsafe_schemeless_port_display} context"
    unsafe_extra_tail_display = "Custom https://api.github.com/repos/capy/spaces/security-advisories-extra context"
    unsafe_encoded_display = "Custom https://api.github.com/repos/capy/spaces/security%2Dadvisories context"
    unsafe_encoded_owner_repo_display = "Custom https://api.github.com/repos/capy%2Fspaces/security-advisories context"
    unsafe_schemeless_encoded_owner_repo_display = "Custom api.github.com/repos/capy%2Fspaces/security-advisories context"
    assert not capy_memory._github_security_advisories_display_name_is_unsafe(
        "Custom https://api.github.com.evil.test/repos/capy/spaces/security-advisories context"
    )
    assert not capy_memory._github_security_advisories_display_name_is_unsafe(
        "Custom https://github.com/repos/capy/spaces/security-advisories context"
    )
    assert capy_memory._github_security_advisories_display_name_is_unsafe(unsafe_extra_tail_display)
    assert capy_memory._github_security_advisories_display_name_is_unsafe(unsafe_encoded_display)
    assert capy_memory._github_security_advisories_display_name_is_unsafe(unsafe_encoded_owner_repo_display)
    assert capy_memory._github_security_advisories_display_name_is_unsafe(
        unsafe_schemeless_encoded_owner_repo_display
    )
    cases = [
        ("title-userinfo", {"title": unsafe_userinfo_display}, unsafe_userinfo_origin),
        ("display-name-port", {"display_name": unsafe_port_display}, unsafe_port_origin),
        ("name-userinfo", {"name": unsafe_userinfo_display}, unsafe_userinfo_origin),
        ("schemeless-title", {"title": unsafe_schemeless_display}, unsafe_userinfo_origin),
        ("schemeless-display-name", {"display_name": unsafe_schemeless_port_display}, unsafe_port_origin),
        ("schemeless-name", {"name": unsafe_schemeless_display}, unsafe_userinfo_origin),
        ("embedded-url-display-name", {"display_name": unsafe_embedded_url_display}, unsafe_userinfo_origin),
        ("embedded-schemeless-title", {"title": unsafe_embedded_schemeless_display}, unsafe_port_origin),
        ("extra-tail-display-name", {"display_name": unsafe_extra_tail_display}, unsafe_port_origin),
        ("encoded-title", {"title": unsafe_encoded_display}, unsafe_userinfo_origin),
        ("encoded-owner-repo-title", {"title": unsafe_encoded_owner_repo_display}, unsafe_userinfo_origin),
        (
            "schemeless-encoded-owner-repo-display-name",
            {"display_name": unsafe_schemeless_encoded_owner_repo_display},
            unsafe_port_origin,
        ),
    ]

    for suffix, display_fields, unsafe_origin in cases:
        source_id = f"ghsa-route-display-{suffix}"
        receipt = register_source_reference({
            "source_id": source_id,
            "origin_uri": unsafe_origin,
            **display_fields,
        })
        assert receipt["origin_uri"] == f"capy-memory://{source_id}"

