def test_public_memory_hits_neutralize_legacy_github_security_advisories_route_display_name(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    init_memory_tree()

    space_id = "public-hit-space"
    now = "2026-06-06T00:00:00+00:00"
    cases = [
        (
            "legacy-ghsa-public-hit",
            "Custom api.github.com/repos/capy/spaces/security-advisories context",
        ),
        (
            "legacy-ghsa-userinfo-port-public-hit",
            "Custom https://user:pass@api.github.com:444/repos/capy/spaces/security-advisories context",
        ),
        (
            "legacy-ghsa-extra-tail-public-hit",
            "Custom https://api.github.com/repos/capy/spaces/security-advisories-extra context",
        ),
        (
            "legacy-ghsa-encoded-public-hit",
            "Custom https://api.github.com/repos/capy/spaces/security%2Dadvisories context",
        ),
        (
            "legacy-ghsa-encoded-owner-repo-public-hit",
            "Custom https://api.github.com/repos/capy%2Fspaces/security-advisories context",
        ),
        (
            "legacy-ghsa-schemeless-encoded-owner-repo-public-hit",
            "Custom api.github.com/repos/capy%2Fspaces/security-advisories context",
        ),
    ]
    with sqlite3.connect(memory_tree_db_path()) as conn:
        for source_id, unsafe_display_name in cases:
            origin_uri = f"capy-memory://{source_id}"
            conn.execute(
                """
                INSERT INTO sources (
                    source_id, source_type, display_name, origin_uri, origin_kind, space_id,
                    freshness_status, last_checked_at, created_at, updated_at
                )
                VALUES (?, 'github', ?, ?, 'auto_fetch', ?, 'stale', ?, ?, ?)
                """,
                (source_id, unsafe_display_name, origin_uri, space_id, now, now, now),
            )
            conn.execute(
                """
                INSERT INTO chunks (
                    chunk_id, source_id, source_ref, content_path, summary, approx_tokens,
                    lifecycle_status, redaction_status, created_at, updated_at
                )
                VALUES (?, ?, ?, ?, ?, 8, 'admitted', 'none', ?, ?)
                """,
                (
                    f"{source_id}-chunk",
                    source_id,
                    origin_uri,
                    str(root / "vault" / f"{source_id}.md"),
                    "Metadata hit for public memory route leak regression.",
                    now,
                    now,
                ),
            )

    search = search_memory("metadata", limit=len(cases))
    relevant = relevant_memory_for_space(space_id, limit=len(cases))

    for payload in (search, relevant):
        hits_by_source = {hit["source_id"]: hit for hit in payload["results"]}
        assert set(hits_by_source) == {source_id for source_id, _display_name in cases}
        for source_id, _display_name in cases:
            hit = hits_by_source[source_id]
            assert hit["origin_uri"] == f"capy-memory://{source_id}"
            assert hit["title"] == source_id

    serialized = json.dumps({"search": search, "relevant": relevant}, sort_keys=True).lower()
    for unsafe in (
        "api.github.com/repos",
        "api.github.com/repos/capy/spaces/security-advisories",
        "api.github.com/repos/capy%2fspaces/security-advisories",
        "security-advisories",
        "security%2dadvisories",
        "user:pass",
        "api.github.com:444",
        "access_token",
        "secret_value_do_not_leak",
        "secrets",
        "token",
    ):
        assert unsafe not in serialized


