def test_queue_due_source_refresh_jobs_preserves_hidden_github_security_advisories_fetch_origin(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()

    clean_fetch_origin = "https://api.github.com/repos/capy/spaces/security-advisories"
    public_origin = "github security advisories capy/spaces"
    receipt = register_source_reference({
        "source_id": "github-security-advisories-due-requeue-hidden-fetch",
        "title": "GitHub Security Advisories Due Requeue Hidden Fetch",
        "origin_uri": "https://api.github.com/repos/capy/spaces/security-advisories?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt",
    })
    body = json.dumps([{
        "ghsa_id": "GHSA-abcd-1234-efgh",
        "cve_id": "CVE-2026-12345",
        "severity": "high",
        "state": "published",
        "created_at": "2026-06-01T10:00:00Z",
        "updated_at": "2026-06-02T11:00:00Z",
        "published_at": "2026-06-03T12:00:00Z",
        "withdrawn_at": None,
        "description": "Raw advisory description must not persist.",
        "vulnerabilities": [{"package": {"name": "metadata-package"}}],
    }]).encode("utf-8")
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def geturl(self):
            return clean_fetch_origin

        def read(self, _limit=-1):
            return body

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.headers.get("Accept")})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    first_result = run_source_refresh_jobs(limit=1)
    due_result = queue_due_source_refresh_jobs(limit=1, now="2099-01-01T00:00:00Z")
    with sqlite3.connect(memory_tree_db_path()) as conn:
        requeued_payload = json.loads(conn.execute(
            "SELECT payload_json FROM jobs WHERE job_id = ?",
            (receipt["job_id"],),
        ).fetchone()[0])
    public_serialized = json.dumps({"receipt": receipt, "first_result": first_result, "due_result": due_result}, sort_keys=True).lower()

    assert calls == [{"url": clean_fetch_origin, "timeout": 8, "accept": "application/json"}]
    assert receipt["origin_uri"] == public_origin
    assert first_result["processed"] == 1
    assert first_result["jobs"][0]["status"] == "completed"
    assert due_result["queued"] == 1
    assert due_result["jobs"][0]["origin_uri"] == public_origin
    assert requeued_payload["origin_uri"] == public_origin
    assert requeued_payload["fetch_origin_uri"] == clean_fetch_origin
    assert requeued_payload["source_refresh_kind"] == "github_security_advisories"
    for unsafe in (
        "api.github.com/repos/capy/spaces/security-advisories",
        "access_token",
        "raw-prompt",
        "raw prompt",
        "secret_value_do_not_leak",
        "api_key",
        "body",
        "raw advisory description",
        "vulnerabilities",
        "renderer",
        "<script",
        "token",
    ):
        assert unsafe not in public_serialized


