@pytest.mark.parametrize(("case", "drifted_final_url"), [
    ("query", "https://api.github.com/repos/capy/spaces/code-scanning/default-setup?access_token=SECRET_VALUE_DO_NOT_LEAK"),
    ("fragment", "https://api.github.com/repos/capy/spaces/code-scanning/default-setup#raw-prompt"),
    ("userinfo", "https://octo-capy:SECRET_VALUE_DO_NOT_LEAK@api.github.com/repos/capy/spaces/code-scanning/default-setup"),
    ("different-repo", "https://api.github.com/repos/capy/other/code-scanning/default-setup"),
    ("different-path", "https://api.github.com/repos/capy/spaces/code-scanning/default-setup/raw"),
    ("different-host", "https://api.github.com.evil.example/repos/capy/spaces/code-scanning/default-setup"),
])
def test_run_source_refresh_jobs_default_fetcher_rejects_github_code_scanning_default_setup_final_url_drift_before_body_read_relevant_memory_empty(tmp_path, monkeypatch, case, drifted_final_url):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    source_id = f"github-code-scanning-default-setup-final-url-drift-{case}"
    clean_origin = "https://api.github.com/repos/capy/spaces/code-scanning/default-setup"
    receipt = register_source_reference({
        "source_id": source_id,
        "title": "GitHub Code Scanning Default Setup Final URL Drift",
        "origin_uri": clean_origin,
    })
    body_sentinel = "DEFAULT_SETUP_DRIFT_SENTINEL renderer raw prompt source html script data API-auth"
    hostile_body = json.dumps(_github_code_scanning_default_setup_fixture(
        state="configured",
        ignored={
            "body": body_sentinel,
            "source": "raw prompt SECRET_VALUE_DO_NOT_LEAK",
            "renderer": "<script>render()</script>",
            "data": {"access_token": "SECRET_VALUE_DO_NOT_LEAK"},
            "api_auth": "SECRET_VALUE_DO_NOT_LEAK",
        },
    )).encode("utf-8")
    calls = []
    read_calls = []

    assert capy_memory._github_code_scanning_default_setup_final_url_matches_origin(clean_origin, clean_origin) is True
    assert capy_memory._github_code_scanning_default_setup_final_url_matches_origin(clean_origin, drifted_final_url) is False

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def geturl(self):
            return drifted_final_url

        def read(self, _limit=-1):
            read_calls.append(_limit)
            return hostile_body

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.headers.get("Accept")})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    result = run_source_refresh_jobs(limit=1)
    jobs = list_source_refresh_jobs(limit=5)
    catalog = capy_memory.source_catalog(limit=5)
    search = search_memory("default setup drift sentinel", limit=5)
    relevant = relevant_memory_for_space("code-scanning-default-setup-drift-space", limit=5)
    serialized = json.dumps({
        "result": result,
        "jobs": jobs,
        "catalog": catalog,
        "search": search,
        "relevant": relevant,
    }, sort_keys=True).lower()

    assert calls == [{"url": clean_origin, "timeout": 8, "accept": "application/json"}]
    assert read_calls == []
    assert result["processed"] == 1
    assert result["jobs"][0]["job_id"] == receipt["job_id"]
    assert result["jobs"][0]["status"] == "pending"
    assert result["jobs"][0]["error"] == "refresh failed"
    assert not (root / "vault" / f"{source_id}.md").exists()
    assert search["results"] == []
    assert relevant["results"] == []
    for unsafe in (
        drifted_final_url.lower(),
        "api.github.com/repos/capy/spaces/code-scanning/default-setup",
        "api.github.com.evil.example",
        "octo-capy",
        "secret_value_do_not_leak",
        "access_token",
        "raw-prompt",
        "default_setup_drift_sentinel",
        "raw prompt",
        "ignore previous instructions",
        "renderer",
        '\"source\":',
        '\"html\":',
        '\"script\":',
        '\"data\":',
        "api_auth",
        "api-auth",
        "<script",
        "render()",
    ):
        assert unsafe not in serialized


