    drifted_final_url = "https://api.github.com/repos/evil/private/code-scanning/alerts/17/instances?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt"
    hostile_body = json.dumps([
        {
            "ref": "refs/heads/main",
            "analysis_key": "CODE_SCANNING_ALERT_INSTANCES_FINAL_URL_DRIFT_SENTINEL",
            "category": "/language:javascript",
            "state": "open",
            "commit_sha": "abcdef1234567890abcdef1234567890abcdef12",
            "location": {"path": "src/SECRET_VALUE_DO_NOT_LEAK.js", "start_line": 12},
            "message": {"text": "raw_prompt sentinel should not be read"},
            "renderer": "<script>render()</script>",
            "source": "raw source html script data API-auth body",
            "html": "<script>exfiltrate()</script>",
            "script": "steal(SECRET_VALUE_DO_NOT_LEAK)",
            "data": {"api_auth": "SECRET_VALUE_DO_NOT_LEAK", "token": "ghp_SECRET_VALUE_DO_NOT_LEAK"},
            "url": "https://api.github.com/repos/evil/private/code-scanning/alerts/17/instances?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt",
        }
    ]).encode("utf-8")
    calls = []
    read_calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def geturl(self):
            return drifted_final_url

        def read(self, _limit=-1):
            read_calls.append(_limit)
            return hostile_body

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.headers.get("Accept")})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

