    serialized = json.dumps({
        "result": result,
        "jobs": jobs,
        "catalog": catalog,
        "search": search,
        "relevant": relevant,
    }, sort_keys=True).lower()

    assert calls == [{"url": clean_origin, "timeout": 8, "accept": "application/json"}]
    assert read_calls == []
    assert result["processed"] == 1
    assert result["jobs"][0]["job_id"] == receipt["job_id"]
    assert result["jobs"][0]["status"] == "pending"
    assert result["jobs"][0]["error"] == "refresh failed"
    assert jobs["jobs"][0]["status"] == "pending"
    assert not (root / "vault" / "github-code-scanning-alert-instances-final-url-drift.md").exists()
    assert search["results"] == []
    assert relevant["results"] == []
    for unsafe in (
        drifted_final_url.lower(),
        "access_token",
        "secret_value_do_not_leak",
        "raw-prompt",
        "raw_prompt",
        "code_scanning_alert_instances_final_url_drift_sentinel",
        "renderer",
        '"source":',
        '"html":',
        '"script":',
        '"data":',
        "api_auth",
        "api-auth",
        "ghp_",
        "token",
        "evil/private",
        "raw source html script data",
        "<script",
        "steal(",
        "render()",
        "exfiltrate()",
    ):
        assert unsafe not in serialized


