def test_queue_due_source_refresh_jobs_preserves_github_code_scanning_analyses_hidden_fetch_origin(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    receipt = register_source_reference({
        "source_id": "github-code-scanning-analyses-due-requeue",
        "title": "GitHub Code Scanning Analyses Due Requeue",
        "origin_uri": "https://api.github.com/repos/capy/spaces/code-scanning/analyses?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt",
    })
    canonical_fetch_origin = "https://api.github.com/repos/capy/spaces/code-scanning/analyses"
    public_origin = "github code scanning analyses capy/spaces"
    payloads = [
        _github_code_scanning_analyses_fixture(),
        _github_code_scanning_analyses_fixture({
            "id": 201,
            "ref": "refs/heads/main",
            "category": "/language:javascript",
            "analysis_key": "codeql-due",
            "commit_sha": "fedcba654321fedcba654321fedcba654321fedc",
            "results_count": 7,
            "rules_count": 21,
            "tool": {"name": "CodeQL", "version": "2.18.0"},
            "created_at": "2026-06-04T12:00:00Z",
        }),
    ]
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}
        def __init__(self, payload): self.payload = payload
        def __enter__(self): return self
        def __exit__(self, *_exc): return False
        def geturl(self): return canonical_fetch_origin
        def read(self, _limit=-1): return json.dumps(self.payload).encode("utf-8")

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.headers.get("Accept")})
        assert payloads, "unexpected code scanning analyses fetch after due requeue"
        return FakeResponse(payloads.pop(0))

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    first_result = run_source_refresh_jobs(limit=1)
    with sqlite3.connect(memory_tree_db_path()) as conn:
        conn.execute(
            """
            UPDATE sources
            SET freshness_status = 'stale', last_checked_at = '2026-06-04T00:00:00+00:00'
            WHERE source_id = ?
            """,
            (receipt["source_id"],),
        )
    due_result = queue_due_source_refresh_jobs(limit=1, now="2026-06-05T00:00:00+00:00")
    with sqlite3.connect(memory_tree_db_path()) as conn:
        requeued_payload = json.loads(conn.execute(
            "SELECT payload_json FROM jobs WHERE job_id = ?",
            (receipt["job_id"],),
        ).fetchone()[0])
    second_result = run_source_refresh_jobs(limit=1, queue_due=False)
    with sqlite3.connect(memory_tree_db_path()) as conn:
        source_origin = conn.execute(
            "SELECT origin_uri FROM sources WHERE source_id = ?",
            (receipt["source_id"],),
        ).fetchone()[0]
    persisted = (root / "vault" / f"{receipt['source_id']}.md").read_text(encoding="utf-8").lower()
    catalog = capy_memory.source_catalog(limit=5)
    catalog_source = next(
        source
        for connector in catalog["connectors"]
        for source in connector["sources"]
        if source["source_id"] == receipt["source_id"]
    )
    search = search_memory("code scanning analyses", limit=5)
    public_serialized = json.dumps({
        "receipt": receipt,
        "first_result": first_result,
        "due_result": due_result,
        "second_result": second_result,
        "source_origin": source_origin,
        "catalog": catalog,
        "search": search,
    }, sort_keys=True).lower()

    assert calls == [
        {"url": canonical_fetch_origin, "timeout": 8, "accept": "application/json"},
        {"url": canonical_fetch_origin, "timeout": 8, "accept": "application/json"},
    ]
    assert receipt["origin_uri"] == public_origin
    assert first_result["processed"] == 1
    assert first_result["jobs"][0]["status"] == "completed"
    assert due_result["queued"] == 1
    assert due_result["jobs"][0]["origin_uri"] == public_origin
    assert requeued_payload["origin_uri"] == public_origin
    assert requeued_payload["fetch_origin_uri"] == canonical_fetch_origin
    assert requeued_payload["source_refresh_kind"] == "github_code_scanning_analyses"
    assert second_result["processed"] == 1
    assert second_result["jobs"][0]["status"] == "completed"
    assert source_origin == public_origin
    assert catalog_source["origin_uri"] == public_origin
    assert search["results"][0]["source_id"] == receipt["source_id"]
    assert "analysis count: 1" in persisted
    assert "analysis #201" in persisted
    assert "analysis: codeql-due" in persisted
    assert "results: 7" in persisted
    assert "origin_uri: github code scanning analyses capy/spaces" in persisted
    for unsafe in (
        "api.github.com/repos/capy/spaces/code-scanning/analyses",
        "access_token",
        "raw-prompt",
        "secret_value_do_not_leak",
        "url:",
        "raw analysis error",
        "raw analysis warning",
    ):
        assert unsafe not in public_serialized
        assert unsafe not in persisted


