def test_register_source_reference_preserves_github_code_scanning_single_alert_hidden_fetch_origin_kind(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    init_memory_tree()

    dirty_origin = "https://api.github.com/repos/capy/spaces/code-scanning/alerts/17?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt"
    public_origin = "github code scanning alert capy/spaces #17"
    clean_fetch_origin = "https://api.github.com/repos/capy/spaces/code-scanning/alerts/17"
    receipt = register_source_reference({
        "source_id": "github-code-scanning-single-alert-hidden-fetch-origin-kind",
        "title": "GitHub Code Scanning Single Alert Hidden Fetch Origin Kind",
        "origin_uri": dirty_origin,
    })
    catalog = capy_memory.source_catalog(limit=10)
    jobs = list_source_refresh_jobs(limit=10)
    with sqlite3.connect(memory_tree_db_path()) as conn:
        stored_source_origin = conn.execute(
            "SELECT origin_uri FROM sources WHERE source_id = ?",
            ("github-code-scanning-single-alert-hidden-fetch-origin-kind",),
        ).fetchone()[0]
        queued_payload = json.loads(conn.execute(
            "SELECT payload_json FROM jobs WHERE job_id = ?",
            (receipt["job_id"],),
        ).fetchone()[0])

    public_serialized = json.dumps({"receipt": receipt, "catalog": catalog, "jobs": jobs}, sort_keys=True).lower()
    queued_serialized = json.dumps(queued_payload, sort_keys=True).lower()

    assert receipt["origin_uri"] == public_origin
    assert stored_source_origin == public_origin
    assert jobs["jobs"][0]["origin_uri"] == public_origin
    assert public_origin in public_serialized
    assert queued_payload["origin_uri"] == public_origin
    assert queued_payload["fetch_origin_uri"] == clean_fetch_origin
    assert queued_payload["source_refresh_kind"] == "github_code_scanning_single_alert"
    assert clean_fetch_origin in queued_serialized
    assert "access_token" not in queued_serialized
    assert "raw-prompt" not in queued_serialized
    assert "secret_value_do_not_leak" not in queued_serialized
    for unsafe in (
        "api.github.com/repos/capy/spaces/code-scanning/alerts/17",
        "access_token",
        "raw-prompt",
        "raw prompt",
        "secret_value_do_not_leak",
        "token",
    ):
        assert unsafe not in public_serialized


