def test_queue_due_source_refresh_jobs_preserves_github_secret_scanning_scan_history_hidden_fetch_origin(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    public_origin = "github secret scanning scan history capy/spaces"
    clean_fetch_origin = "https://api.github.com/repos/capy/spaces/secret-scanning/scan-history"
    receipt = register_source_reference({
        "source_id": "github-secret-scanning-scan-history-due-legacy",
        "title": "GitHub Secret Scanning Scan History Due Legacy",
        "origin_uri": "https://api.github.com/repos/capy/spaces/secret-scanning/scan-history?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt",
    })
    legacy_payload = {
        "source_id": receipt["source_id"],
        "origin_uri": public_origin,
        "refresh_interval_seconds": 3600,
    }
    with sqlite3.connect(memory_tree_db_path()) as conn:
        conn.execute(
            """
            UPDATE jobs
            SET payload_json = ?, status = 'completed', attempts = 1,
                updated_at = '2026-06-13T00:00:00+00:00'
            WHERE job_id = ?
            """,
            (json.dumps(legacy_payload, sort_keys=True, separators=(",", ":")), receipt["job_id"]),
        )
        conn.execute(
            """
            UPDATE sources
            SET origin_uri = ?, freshness_status = 'stale',
                last_checked_at = '2026-06-13T00:00:00+00:00',
                updated_at = '2026-06-13T00:00:00+00:00'
            WHERE source_id = ?
            """,
            (public_origin, receipt["source_id"]),
        )

    queued = queue_due_source_refresh_jobs(limit=1, now="2026-06-14T00:00:00+00:00")
    with sqlite3.connect(memory_tree_db_path()) as conn:
        queued_payload = json.loads(conn.execute(
            "SELECT payload_json FROM jobs WHERE job_id = ?",
            (receipt["job_id"],),
        ).fetchone()[0])
    public_catalog = capy_memory.source_catalog(limit=5)
    public_jobs = list_source_refresh_jobs(limit=5)
    public_serialized = json.dumps({
        "queued": queued,
        "catalog": public_catalog,
        "jobs": public_jobs,
    }, sort_keys=True).lower()
    catalog_sources = [
        source
        for connector in public_catalog["connectors"]
        for source in connector["sources"]
    ]

    assert queued["queued"] == 1
    assert queued["jobs"][0]["origin_uri"] == public_origin
    assert queued_payload["origin_uri"] == public_origin
    assert queued_payload["fetch_origin_uri"] == clean_fetch_origin
    assert queued_payload["source_refresh_kind"] == "github_secret_scanning_scan_history"
    assert any(source["origin_uri"] == public_origin for source in catalog_sources)
    assert public_jobs["jobs"][0]["origin_uri"] == public_origin
    for unsafe in (
        "api.github.com",
        "access_token",
        "secret_value_do_not_leak",
        "raw-prompt",
        "#raw-prompt",
    ):
        assert unsafe not in public_serialized


