def test_run_source_refresh_jobs_default_fetcher_ingests_github_secret_scanning_single_alert_metadata_only(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    receipt = register_source_reference({
        "source_id": "github-single-alert-source-refresh",
        "title": "GitHub Secret Scanning Single Alert Source Refresh",
        "origin_uri": "https://api.github.com/repos/capy/spaces/secret-scanning/alerts/37?access_token=***#raw-prompt",
    })
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}
        def __enter__(self): return self
        def __exit__(self, *_exc): return False
        def read(self, _limit=-1): return json.dumps(_github_secret_scanning_single_alert_fixture()).encode("utf-8")

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.headers.get("Accept")})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    result = run_source_refresh_jobs(limit=1)
    persisted = (root / "vault" / "github-single-alert-source-refresh.md").read_text(encoding="utf-8").lower()
    search = search_memory("secret scanning alert", limit=5)
    serialized = json.dumps({"result": result, "search": search}, sort_keys=True).lower()

    assert receipt["origin_uri"] == "github secret scanning alert capy/spaces #37"
    assert calls == [{"url": "https://api.github.com/repos/capy/spaces/secret-scanning/alerts/37?hide_secret=true", "timeout": 8, "accept": "application/json"}]
    assert result["processed"] == 1
    assert result["jobs"][0]["job_id"] == receipt["job_id"]
    assert result["jobs"][0]["status"] == "completed"
    assert search["results"][0]["source_id"] == "github-single-alert-source-refresh"
    assert "github secret scanning alert #37 for capy/spaces" in persisted
    for safe in (
        "state: open", "secret type: adafruit_io_key", "provider: adafruit", "provider slug: adafruit",
        "validity: active", "publicly leaked: false", "multi repo: false", "first location: readme.md:12-12",
        "has more locations: false", "assigned to: octo-reviewer", "created_at: 2026-06-04t10:00:00z",
        "updated_at: 2026-06-04t11:00:00z", "push protection bypassed: false",
        "origin_uri: github secret scanning alert capy/spaces #37",
    ):
        assert safe in persisted
    for unsafe in (
        "api.github.com/repos/capy/spaces/secret-scanning/alerts/37", "hide_secret=true", "access_token", "raw-prompt",
        "secret_value_do_not_leak", "secret_type_display_name", "adafruit io key display name", "resolution comment",
        "resolution_comment", "html_url", "locations_url", "alert count:",
    ):
        assert unsafe not in serialized
        assert unsafe not in persisted


