def test_run_source_refresh_jobs_queue_due_rejects_legacy_github_secret_scanning_single_alert_malformed_origin_before_fetch(tmp_path, monkeypatch, source_id, raw_origin, unsafe_markers):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    clean_origin = "https://api.github.com/repos/capy/spaces/secret-scanning/alerts/37"
    receipt = register_source_reference({"source_id": source_id, "title": "GitHub Secret Scanning Single Alert Due Legacy Raw", "origin_uri": clean_origin, "refresh_interval_seconds": 60})
    stale_checked_at = "2026-06-01T10:00:00+00:00"
    fresh_now = "2026-06-01T10:02:30+00:00"
    legacy_payload = {"source_id": source_id, "origin_uri": raw_origin, "refresh_interval_seconds": 60}
    with sqlite3.connect(memory_tree_db_path()) as conn:
        conn.execute("UPDATE jobs SET payload_json = ?, status = 'completed', attempts = 2, updated_at = ? WHERE job_id = ?", (json.dumps(legacy_payload, sort_keys=True, separators=(",", ":")), stale_checked_at, receipt["job_id"]))
        conn.execute("UPDATE sources SET origin_uri = ?, freshness_status = 'stale', last_checked_at = ?, updated_at = ? WHERE source_id = ?", (raw_origin, stale_checked_at, stale_checked_at, source_id))
    calls = []
    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout})
        raise AssertionError("legacy raw single secret-scanning alert origin must fail before fetch")
    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)
    monkeypatch.setattr(capy_memory, "_now_iso", lambda: fresh_now)

    result = run_source_refresh_jobs(limit=1, queue_due=True)
    jobs = list_source_refresh_jobs(limit=5)
    search = search_memory("single alert", limit=5)
    with sqlite3.connect(memory_tree_db_path()) as conn:
        stored_job_payload = json.loads(conn.execute("SELECT payload_json FROM jobs WHERE job_id = ?", (receipt["job_id"],)).fetchone()[0])
    serialized = json.dumps({"result": result, "jobs": jobs, "search": search}, sort_keys=True).lower()
    stored_payload_serialized = json.dumps(stored_job_payload, sort_keys=True).lower()

    assert calls == []
    assert result["processed"] == 1
    assert result["jobs"][0]["job_id"] == receipt["job_id"]
    assert result["jobs"][0]["status"] == "pending"
    assert result["jobs"][0]["error"] == "refresh failed"
    assert jobs["jobs"][0]["origin_uri"] == f"capy-memory://{source_id}"
    assert stored_job_payload == {"origin_uri": f"capy-memory://{source_id}", "refresh_interval_seconds": 60, "source_id": source_id}
    assert search["results"] == []
    assert not (root / "vault" / f"{source_id}.md").exists()
    for unsafe in (clean_origin, "github_pat_", "ghp_", *unsafe_markers):
        assert unsafe not in serialized
        assert unsafe not in stored_payload_serialized


