def test_list_source_refresh_jobs_and_source_catalog_sanitize_legacy_raw_github_secret_scanning_alerts_before_due_requeue(
    tmp_path,
    monkeypatch,
):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    init_memory_tree()
    exact_source_id = "github-ss-alerts-legacy-raw-exact"
    unsafe_source_id = "github-ss-alerts-legacy-raw-query"
    clean_origin = "https://api.github.com/repos/capy/spaces/secret-scanning/alerts"
    public_origin = "github secret scanning alerts capy/spaces"
    unsafe_origin = (
        "https://octo-capy:SECRET_VALUE_DO_NOT_LEAK@api.github.com"
        "/repos/capy/spaces/secret-scanning/alerts?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt"
    )
    exact_receipt = register_source_reference({
        "source_id": exact_source_id,
        "title": "GitHub Secret Scanning Alerts Legacy Raw Exact",
        "origin_uri": clean_origin,
        "refresh_interval_seconds": 60,
    })
    unsafe_receipt = register_source_reference({
        "source_id": unsafe_source_id,
        "title": "GitHub Secret Scanning Alerts Legacy Raw Unsafe",
        "origin_uri": clean_origin,
        "refresh_interval_seconds": 60,
    })
    with sqlite3.connect(memory_tree_db_path()) as conn:
        for source_id, job_id, origin_uri in (
            (exact_source_id, exact_receipt["job_id"], clean_origin),
            (unsafe_source_id, unsafe_receipt["job_id"], unsafe_origin),
        ):
            legacy_payload = {
                "source_id": source_id,
                "origin_uri": origin_uri,
                "refresh_interval_seconds": 60,
            }
            conn.execute(
                "UPDATE jobs SET payload_json = ?, status = 'pending', attempts = 0 WHERE job_id = ?",
                (json.dumps(legacy_payload, sort_keys=True, separators=(",", ":")), job_id),
            )
            conn.execute(
                "UPDATE sources SET origin_uri = ?, freshness_status = 'stale' WHERE source_id = ?",
                (origin_uri, source_id),
            )

    public_catalog = capy_memory.source_catalog(limit=5)
    public_jobs = list_source_refresh_jobs(limit=5)
    public_serialized = json.dumps({"catalog": public_catalog, "jobs": public_jobs}, sort_keys=True).lower()
    catalog_sources = [
        source
        for connector in public_catalog["connectors"]
        for source in connector["sources"]
    ]
    exact_catalog_source = next(source for source in catalog_sources if source["source_id"] == exact_source_id)
    unsafe_catalog_source = next(source for source in catalog_sources if source["source_id"] == unsafe_source_id)
    exact_job = next(job for job in public_jobs["jobs"] if job["source_id"] == exact_source_id)
    unsafe_job = next(job for job in public_jobs["jobs"] if job["source_id"] == unsafe_source_id)

    assert exact_job["origin_uri"] == public_origin
    assert exact_catalog_source["origin_uri"] == public_origin
    assert unsafe_job["origin_uri"] == f"capy-memory://{unsafe_source_id}"
    assert unsafe_catalog_source["origin_uri"] == f"capy-memory://{unsafe_source_id}"
    assert public_origin in public_serialized
    for unsafe in (
        "https://api.github.com",
        "api.github.com",
        "octo-capy",
        "secret_value_do_not_leak",
        "access_token",
        "raw-prompt",
        "hide_secret=true",
    ):
        assert unsafe not in public_serialized


