def _assert_secret_scanning_final_url_drift_rejected_before_body_read(
    tmp_path,
    monkeypatch,
    *,
    source_id,
    origin_uri,
    final_url,
    expected_request_url,
):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    receipt = register_source_reference({
        "source_id": source_id,
        "title": "GitHub Secret Scanning Final URL Drift",
        "origin_uri": origin_uri,
    })
    body_reads = []
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def geturl(self):
            return final_url

        def read(self, _limit=-1):
            body_reads.append(_limit)
            raise AssertionError("secret scanning final URL drift must fail before body read")

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.headers.get("Accept")})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    result = run_source_refresh_jobs(limit=1)
    jobs = list_source_refresh_jobs(limit=5)
    catalog = capy_memory.source_catalog(limit=5)
    search = search_memory("secret scanning drift evidence", limit=5)
    relevant = relevant_memory_for_space("space-secret-scanning-final-url-drift", limit=5)
    serialized = json.dumps(
        {"result": result, "jobs": jobs, "catalog": catalog, "search": search, "relevant": relevant},
        sort_keys=True,
    ).lower()

    assert calls == [{"url": expected_request_url, "timeout": 8, "accept": "application/json"}]
    assert body_reads == []
    assert result["processed"] == 1
    assert result["jobs"][0]["job_id"] == receipt["job_id"]
    assert result["jobs"][0]["status"] == "pending"
    assert result["jobs"][0]["error"] == "refresh failed"
    assert jobs["jobs"][0]["status"] == "pending"
    assert search["results"] == []
    assert relevant["results"] == []
    assert not (root / "vault" / f"{source_id}.md").exists()
    for unsafe in (
        "secret_value_do_not_leak",
        "access_token",
        "api_key",
        "raw-prompt",
        "https://api.github.com",
        "/repos/capy/spaces/secret-scanning",
        "renderer",
        "<script",
    ):
        assert unsafe not in serialized


