def test_run_source_refresh_jobs_queue_due_rejects_legacy_github_secret_scanning_alert_locations_raw_query_fragment_before_fetch(
    tmp_path,
    monkeypatch,
):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    source_id = "github-alert-locations-due-legacy-raw"
    clean_origin = "https://api.github.com/repos/capy/spaces/secret-scanning/alerts/31/locations"
    raw_origin = clean_origin + "?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt"
    receipt = register_source_reference({
        "source_id": source_id,
        "title": "GitHub Secret Scanning Alert Locations Due Legacy Raw",
        "origin_uri": clean_origin,
        "refresh_interval_seconds": 60,
    })
    stale_checked_at = "2026-06-01T10:00:00+00:00"
    fresh_now = "2026-06-01T10:02:30+00:00"
    legacy_payload = {"source_id": source_id, "origin_uri": raw_origin, "refresh_interval_seconds": 60}
    with sqlite3.connect(memory_tree_db_path()) as conn:
        conn.execute(
            "UPDATE jobs SET payload_json = ?, status = 'completed', attempts = 2, updated_at = ? WHERE job_id = ?",
            (json.dumps(legacy_payload, sort_keys=True, separators=(",", ":")), stale_checked_at, receipt["job_id"]),
        )
        conn.execute(
            """
            UPDATE sources
            SET origin_uri = ?, freshness_status = 'stale', last_checked_at = ?, updated_at = ?
            WHERE source_id = ?
            """,
            (raw_origin, stale_checked_at, stale_checked_at, source_id),
        )
    calls = []

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout})
        raise AssertionError("legacy raw secret-scanning alert-locations origin must fail before fetch")

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)
    monkeypatch.setattr(capy_memory, "_now_iso", lambda: fresh_now)

    result = run_source_refresh_jobs(limit=1, queue_due=True)
    jobs = list_source_refresh_jobs(limit=5)
    search = search_memory("alert locations", limit=5)
    with sqlite3.connect(memory_tree_db_path()) as conn:
        stored_job_payload = json.loads(conn.execute(
            "SELECT payload_json FROM jobs WHERE job_id = ?",
            (receipt["job_id"],),
        ).fetchone()[0])
    serialized = json.dumps({"result": result, "jobs": jobs, "search": search}, sort_keys=True).lower()
    stored_payload_serialized = json.dumps(stored_job_payload, sort_keys=True).lower()

    assert calls == []
    assert result["processed"] == 1
    assert result["jobs"][0]["job_id"] == receipt["job_id"]
    assert result["jobs"][0]["status"] == "pending"
    assert result["jobs"][0]["error"] == "refresh failed"
    assert jobs["jobs"][0]["origin_uri"] == f"capy-memory://{source_id}"
    assert stored_job_payload == {
        "origin_uri": f"capy-memory://{source_id}",
        "refresh_interval_seconds": 60,
        "source_id": source_id,
    }
    assert search["results"] == []
    assert not (root / "vault" / f"{source_id}.md").exists()
    for unsafe in (
        clean_origin,
        "hide_secret=true",
        "secret_value_do_not_leak",
        "access_token",
        "raw-prompt",
        "github_pat_",
        "ghp_",
    ):
        assert unsafe not in serialized
        assert unsafe not in stored_payload_serialized


