def test_github_dependency_graph_sbom_due_requeue_preserves_hidden_fetch_metadata(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    public_origin = "github dependency graph sbom capy/spaces"
    canonical_fetch_origin = "https://api.github.com/repos/capy/spaces/dependency-graph/sbom"
    receipt = register_source_reference({
        "source_id": "github-dependency-graph-sbom-due-requeue",
        "title": "GitHub Dependency Graph SBOM Due Requeue",
        "origin_uri": "https://api.github.com/repos/capy/spaces/dependency-graph/sbom?access_token=SECRET#raw-prompt",
    })
    bodies = [
        json.dumps({
            "sbom": {
                "SPDXID": "SPDXRef-DOCUMENT",
                "name": "capy/spaces",
                "packages": [{"name": "requests", "versionInfo": "2.31.0"}],
            },
        }).encode("utf-8"),
        json.dumps({
            "sbom": {
                "SPDXID": "SPDXRef-DOCUMENT",
                "name": "capy/spaces",
                "packages": [{"name": "flask", "versionInfo": "3.0.0"}],
            },
        }).encode("utf-8"),
    ]
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __init__(self, body):
            self._body = body

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def geturl(self):
            return canonical_fetch_origin

        def read(self, _limit=-1):
            return self._body

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.headers.get("Accept")})
        return FakeResponse(bodies.pop(0))

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    first_run = run_source_refresh_jobs(limit=1)
    queued = queue_due_source_refresh_jobs(limit=1, now="2099-01-01T00:00:00Z")
    with sqlite3.connect(memory_tree_db_path()) as conn:
        requeued_payload = json.loads(conn.execute(
            "SELECT payload_json FROM jobs WHERE job_id = ?",
            (receipt["job_id"],),
        ).fetchone()[0])
    second_run = run_source_refresh_jobs(limit=1, queue_due=False)
    search = search_memory("flask", limit=5)
    persisted = (root / "vault" / "github-dependency-graph-sbom-due-requeue.md").read_text(encoding="utf-8").lower()

    assert receipt["origin_uri"] == public_origin
    assert first_run["jobs"][0]["status"] == "completed"
    assert queued["queued"] == 1
    assert queued["jobs"][0]["origin_uri"] == public_origin
    assert requeued_payload["origin_uri"] == public_origin
    assert requeued_payload["fetch_origin_uri"] == canonical_fetch_origin
    assert requeued_payload["source_refresh_kind"] == "github_dependency_graph_sbom"
    assert second_run["jobs"][0]["status"] == "completed"
    assert calls == [
        {"url": canonical_fetch_origin, "timeout": 8, "accept": "application/json"},
        {"url": canonical_fetch_origin, "timeout": 8, "accept": "application/json"},
    ]
    assert search["results"][0]["source_id"] == "github-dependency-graph-sbom-due-requeue"
    assert "package: flask version: 3.0.0" in persisted



def test_run_source_refresh_jobs_default_fetcher_rejects_github_dependency_graph_sbom_json_feed_and_text_fallback(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    feed_id = "github-dependency-graph-sbom-feed-bypass"
    text_id = "github-dependency-graph-sbom-text-bypass"
    register_source_reference({
        "source_id": feed_id,
        "title": "GitHub Dependency Graph SBOM Feed Bypass",
        "origin_uri": "https://api.github.com/repos/capy/spaces/dependency-graph/sbom?access_token=***#raw-prompt",
    })
    register_source_reference({
        "source_id": text_id,
        "title": "GitHub Dependency Graph SBOM Text Bypass",
        "origin_uri": "https://api.github.com/repos/capy/other-space/dependency-graph/sbom?access_token=***#raw-prompt",
    })
    bodies = [
        (
            "application/json; charset=utf-8",
            json.dumps({
                "version": "https://jsonfeed.org/version/1.1",
                "items": [{"title": "SBOM feed bypass", "summary": "safe-looking SBOM feed summary should not persist"}],
                "api_key": "SECRET_VALUE_DO_NOT_LEAK",
            }).encode("utf-8"),
        ),
        ("text/plain; charset=utf-8", b"Summary: safe-looking SBOM text summary should not persist."),
    ]
    calls = []

    class FakeResponse:
        def __init__(self, content_type, body):
            self.headers = {"Content-Type": content_type}
            self._body = body

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def read(self, _limit=-1):
            return self._body

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.headers.get("Accept")})
        content_type, body = bodies.pop(0)
        return FakeResponse(content_type, body)

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    result = run_source_refresh_jobs(limit=2)
    search = search_memory("safe-looking SBOM", limit=5)
    serialized = json.dumps({"result": result, "search": search}, sort_keys=True).lower()

    assert calls == [
        {"url": "https://api.github.com/repos/capy/spaces/dependency-graph/sbom", "timeout": 8, "accept": "application/json"},
        {"url": "https://api.github.com/repos/capy/other-space/dependency-graph/sbom", "timeout": 8, "accept": "application/json"},
    ]
    assert result["processed"] == 2
    assert [job["status"] for job in result["jobs"]] == ["pending", "pending"]
    assert {job["error"] for job in result["jobs"]} == {"refresh failed"}
    assert search["results"] == []
    assert not (root / "vault" / f"{feed_id}.md").exists()
    assert not (root / "vault" / f"{text_id}.md").exists()
    for unsafe in (
        "safe-looking sbom feed summary",
        "safe-looking sbom text summary",
        "secret_value_do_not_leak",
        "api_key",
        "access_token",
        "raw-prompt",
        "api.github.com/repos/capy/spaces/dependency-graph/sbom",
        "api.github.com/repos/capy/other-space/dependency-graph/sbom",
    ):
        assert unsafe not in serialized


