def test_run_source_refresh_jobs_default_fetcher_rejects_oversized_github_dependabot_alerts_payload(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    source_id = "github-dependabot-alerts-oversized"
    receipt = register_source_reference({
        "source_id": source_id,
        "title": "GitHub Dependabot Alerts Oversized Source Refresh",
        "origin_uri": "https://api.github.com/repos/capy/spaces/dependabot/alerts?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt",
    })
    payload = []
    for index in range(1, 102):
        row = {
            "number": index,
            "state": "open",
            "dependency": {
                "package": {"ecosystem": "pip", "name": f"dependabot-overflow-package-{index:03d}"},
                "manifest_path": f"requirements-{index:03d}.txt",
            },
            "security_advisory": {"severity": "high"},
        }
        if index == 1:
            row["security_advisory"].update({
                "ghsa_id": "GHSA-over-flow-0001",
                "cve_id": "CVE-2026-00001",
                "summary": "Oversized advisory text must not persist.",
                "description": "Oversized raw advisory body must not persist.",
            })
            row["url"] = "https://api.github.com/repos/capy/spaces/dependabot/alerts/1"
            row["html_url"] = "https://github.com/capy/spaces/security/dependabot/1"
        if index == 2:
            row["security_vulnerability"] = {
                "severity": "critical",
                "vulnerable_version_range": "<9.9.9",
                "patched_versions": ">=9.9.9",
            }
        payload.append(row)
    body = json.dumps(payload).encode("utf-8")
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def read(self, _limit=-1):
            return body

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.headers.get("Accept")})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    result = run_source_refresh_jobs(limit=1)
    jobs = list_source_refresh_jobs(limit=5)
    search_first = search_memory("dependabot-overflow-package-001", limit=5)
    search_last = search_memory("dependabot-overflow-package-101", limit=5)
    serialized = json.dumps(
        {
            "receipt": receipt,
            "result": result,
            "jobs": jobs,
            "search_first_results": search_first["results"],
            "search_last_results": search_last["results"],
        },
        sort_keys=True,
    ).lower()

    assert calls == [{"url": "https://api.github.com/repos/capy/spaces/dependabot/alerts", "timeout": 8, "accept": "application/json"}]
    assert result["processed"] == 1
    assert result["jobs"][0]["job_id"] == receipt["job_id"]
    assert result["jobs"][0]["status"] == "pending"
    assert result["jobs"][0]["error"] == "refresh failed"
    assert jobs["jobs"][0]["status"] == "pending"
    assert search_first["results"] == []
    assert search_last["results"] == []
    assert not (root / "vault" / f"{source_id}.md").exists()
    for unsafe in (
        "https://api.github.com/repos/capy/spaces/dependabot/alerts",
        "api.github.com/repos/capy/spaces/dependabot/alerts",
        "access_token",
        "raw-prompt",
        "raw_prompt",
        "security_advisory",
        "security_vulnerability",
        "html_url",
        "renderer",
        '\"source\":',
        "html",
        "script",
        "api-auth",
        "secret_value_do_not_leak",
        "oversized advisory text",
        "oversized raw advisory body",
        "<9.9.9",
        ">=9.9.9",
        "ghsa-over-flow",
        "cve-2026",
        "dependabot-overflow-package-001",
        "dependabot-overflow-package-101",
    ):
        assert unsafe not in serialized


def test_queue_due_source_refresh_jobs_preserves_github_dependabot_alerts_hidden_fetch_origin(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    receipt = register_source_reference({
        "source_id": "github-dependabot-alerts-due-requeue",
        "title": "GitHub Dependabot Alerts Due Requeue",
        "origin_uri": "https://api.github.com/repos/capy/spaces/dependabot/alerts?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt",
    })
    canonical_fetch_origin = "https://api.github.com/repos/capy/spaces/dependabot/alerts"
    public_origin = "github dependabot alerts capy/spaces"
    refreshed_payload = [
        {
            "number": 7,
            "state": "open",
            "dependency": {"package": {"ecosystem": "pip", "name": "django"}, "manifest_path": "requirements.txt"},
            "security_advisory": {"severity": "high", "summary": "Advisory text must not persist."},
        }
    ]
    requeued_payload = [
        {
            "number": 8,
            "state": "open",
            "dependency": {
                "package": {"ecosystem": "pip", "name": "django-rest-framework"},
                "manifest_path": "requirements.txt",
            },
            "security_advisory": {"severity": "medium", "summary": "Requeued advisory text must not persist."},
        }
    ]
    payloads = [refreshed_payload, requeued_payload]
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __init__(self, payload):
            self.payload = payload

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def geturl(self):
            return canonical_fetch_origin

        def read(self, _limit=-1):
            return json.dumps(self.payload).encode("utf-8")

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.headers.get("Accept")})
        assert payloads, "unexpected Dependabot alerts list fetch after due requeue"
        return FakeResponse(payloads.pop(0))

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    first_result = run_source_refresh_jobs(limit=1)
    with sqlite3.connect(memory_tree_db_path()) as conn:
        conn.execute(
            """
            UPDATE sources
            SET freshness_status = 'stale', last_checked_at = '2026-06-04T00:00:00+00:00'
            WHERE source_id = ?
            """,
            (receipt["source_id"],),
        )
    due_result = queue_due_source_refresh_jobs(limit=1, now="2026-06-05T00:00:00+00:00")
    with sqlite3.connect(memory_tree_db_path()) as conn:
        stored_requeue_payload = json.loads(conn.execute(
            "SELECT payload_json FROM jobs WHERE job_id = ?",
            (receipt["job_id"],),
        ).fetchone()[0])
    second_result = run_source_refresh_jobs(limit=1, queue_due=False)
    with sqlite3.connect(memory_tree_db_path()) as conn:
        source_origin = conn.execute(
            "SELECT origin_uri FROM sources WHERE source_id = ?",
            (receipt["source_id"],),
        ).fetchone()[0]
    persisted = (root / "vault" / f"{receipt['source_id']}.md").read_text(encoding="utf-8").lower()
    search = search_memory("dependabot", limit=5)
    catalog = capy_memory.source_catalog(limit=5)
    catalog_source = next(
        source
        for connector in catalog["connectors"]
        for source in connector["sources"]
        if source["source_id"] == receipt["source_id"]
    )
    public_serialized = json.dumps({
        "receipt": receipt,
        "first_result": first_result,
        "due_result": due_result,
        "second_result": second_result,
        "source_origin": source_origin,
        "catalog": catalog,
        "search": search,
    }, sort_keys=True).lower()

    assert calls == [
        {"url": canonical_fetch_origin, "timeout": 8, "accept": "application/json"},
        {"url": canonical_fetch_origin, "timeout": 8, "accept": "application/json"},
    ]
    assert receipt["origin_uri"] == public_origin
    assert first_result["processed"] == 1
    assert first_result["jobs"][0]["status"] == "completed"
    assert due_result["queued"] == 1
    assert due_result["jobs"][0]["origin_uri"] == public_origin
    assert stored_requeue_payload["origin_uri"] == public_origin
    assert stored_requeue_payload["fetch_origin_uri"] == canonical_fetch_origin
    assert stored_requeue_payload["source_refresh_kind"] == "github_dependabot_alerts"
    assert second_result["processed"] == 1
    assert second_result["jobs"][0]["status"] == "completed"
    assert source_origin == public_origin
    assert catalog_source["origin_uri"] == public_origin
    assert search["results"][0]["source_id"] == receipt["source_id"]
    assert "github dependabot alerts for capy/spaces" in persisted
    assert "package: django-rest-framework" in persisted
    assert "origin_uri: github dependabot alerts capy/spaces" in persisted
    for unsafe in (
        "api.github.com/repos/capy/spaces/dependabot/alerts",
        "secret_value_do_not_leak",
        "access_token",
        "raw-prompt",
        "advisory text must not persist",
        "requeued advisory text must not persist",
    ):
        assert unsafe not in public_serialized
        assert unsafe not in persisted


def test_github_dependabot_alerts_summarized_refresh_preserves_metadata_only_origin_uri():
    origin_uri = "https://api.github.com/repos/capy/spaces/dependabot/alerts"
    record = capy_memory._refresh_record_from_json(
        "github-dependabot-alerts-summarized",
        origin_uri,
        [
            {
                "number": 7,
                "state": "open",
                "dependency": {"package": {"ecosystem": "pip", "name": "django"}, "manifest_path": "requirements.txt"},
                "security_advisory": {"severity": "high", "summary": "raw advisory body must not persist"},
                "url": "https://api.github.com/repos/capy/spaces/dependabot/alerts/7",
            }
        ],
    )

    summarized = capy_memory._summarized_source_refresh_record(
        source_id="github-dependabot-alerts-summarized",
        origin_uri=origin_uri,
        record=record,
        summarizer=lambda *, record, model_route: {
            "metadata_only": True,
            "title": "Summarized Dependabot alerts",
            "summary": "Model routed metadata-only Dependabot alert digest.",
        },
        model_route_resolution={
            "resolution": "configured",
            "hint": "hint:summarize",
            "resolved_provider": "local",
            "resolved_model": "summarizer",
        },
    )
    serialized = json.dumps(summarized, sort_keys=True).lower()

    assert summarized["origin_uri"] == "github dependabot alerts capy/spaces"
    assert "origin_uri: github dependabot alerts capy/spaces" in summarized["markdown"].lower()
    assert "api.github.com/repos/capy/spaces/dependabot/alerts" not in serialized
    assert "raw advisory body" not in serialized
    assert "access_token" not in serialized


