def test_queue_due_source_refresh_jobs_preserves_github_pages_deployment_hidden_fetch_origin(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    receipt = register_source_reference({
        "source_id": "github-pages-deployment-due-requeue",
        "title": "GitHub Pages Deployment Due Requeue",
        "origin_uri": "https://api.github.com/repos/capy/spaces/pages/deployments/abcdefabcdefabcdefabcdefabcdefabcdefabcd?access_token=***#raw-prompt",
    })
    canonical_fetch_origin = "https://api.github.com/repos/capy/spaces/pages/deployments/abcdefabcdefabcdefabcdefabcdefabcdefabcd"
    public_origin = "github pages deployment capy/spaces abcdefabcdef..."
    payloads = [{"status": "deployment_in_progress", "created_at": "2026-06-01T10:00:00Z"}, {"status": "succeed", "updated_at": "2026-06-01T10:05:00Z"}]
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __init__(self, payload):
            self.payload = payload

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def geturl(self):
            return canonical_fetch_origin

        def read(self, _limit=-1):
            return json.dumps(self.payload).encode("utf-8")

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout})
        assert payloads, "unexpected fetch after due requeue regression coverage"
        return FakeResponse(payloads.pop(0))

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    first_result = run_source_refresh_jobs(limit=1)
    due_result = queue_due_source_refresh_jobs(limit=1, now="2099-01-01T00:00:00Z")
    with sqlite3.connect(memory_tree_db_path()) as conn:
        requeued_payload = json.loads(conn.execute("SELECT payload_json FROM jobs WHERE job_id = ?", (receipt["job_id"],)).fetchone()[0])
    second_result = run_source_refresh_jobs(limit=1, queue_due=False)
    persisted = (root / "vault" / "github-pages-deployment-due-requeue.md").read_text(encoding="utf-8").lower()
    serialized = json.dumps({"receipt": receipt, "first_result": first_result, "due_result": due_result, "second_result": second_result}, sort_keys=True).lower()

    assert calls == [{"url": canonical_fetch_origin, "timeout": 8}, {"url": canonical_fetch_origin, "timeout": 8}]
    assert receipt["origin_uri"] == public_origin
    assert first_result["processed"] == 1
    assert first_result["jobs"][0]["status"] == "completed"
    assert due_result["queued"] == 1
    assert due_result["jobs"][0]["origin_uri"] == public_origin
    assert requeued_payload["origin_uri"] == public_origin
    assert requeued_payload["fetch_origin_uri"] == canonical_fetch_origin
    assert second_result["processed"] == 1
    assert second_result["jobs"][0]["status"] == "completed"
    assert "github pages deployment for capy/spaces abcdefabcdef..." in persisted
    assert "status: succeed" in persisted
    for unsafe in ("api.github.com", "/repos/capy/spaces/pages/deployments/abcdef", "access_token", "raw-prompt", "secret_value_do_not_leak"):
        assert unsafe not in serialized
        assert unsafe not in persisted


