@pytest.mark.parametrize("origin_uri", [
    "https://api.github.com.evil.test/orgs/capy/dependabot/secrets/CAPY_MODE",
    "https://API.github.com/orgs/capy/dependabot/secrets/CAPY_MODE",
    "https://api.github.com:443/orgs/capy/dependabot/secrets/CAPY_MODE",
    "https://ghp_SECRET_VALUE_DO_NOT_LEAK@api.github.com/orgs/capy/dependabot/secrets/CAPY_MODE",
    "https://api.github.com/orgs/capy/dependabot/secrets/CAPY_MODE?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt",
])
def test_default_source_refresh_fetcher_rejects_github_dependabot_org_single_secret_route_abuse_before_fetch(monkeypatch, origin_uri):
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    calls = []

    def fake_refresh_open(*_args, **_kwargs):
        calls.append(_args)
        raise AssertionError("route abuse must be rejected before fetch")

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)
    with pytest.raises(RuntimeError, match="refresh fetcher disabled"):
        capy_memory._default_source_refresh_fetcher(source_id="source", origin_uri=origin_uri)
    assert calls == []


