    receipt = register_source_reference({
        "source_id": "github-dependabot-org-selected-repositories-final-url-drift",
        "title": "GitHub Dependabot organization selected repositories final URL drift",
        "origin_uri": f"{canonical_url}?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt",
        "space_id": "capy",
    })
    selected_repositories_body = json.dumps({
        "total_count": 1,
        "repositories": [
            {
                "id": 101,
                "name": "spaces",
                "full_name": "capy/spaces",
                "private": True,
                "renderer": "<script>SECRET_VALUE_DO_NOT_LEAK</script>",
                "temp_clone_token": "SECRET_VALUE_DO_NOT_LEAK",
                "body": body_sentinel,
            }
        ],
    }).encode("utf-8")
    opened_urls = []
    read_calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def geturl(self):
            return drifted_final_url

        def read(self, _limit=-1):
            read_calls.append("read")
            return selected_repositories_body

    def fake_refresh_open(request, *, timeout):
        opened_urls.append({"url": request.full_url, "timeout": timeout, "accept": request.headers.get("Accept")})
        return FakeResponse()

