def test_github_actions_org_single_secret_route_safety_public_label_and_payload_helpers():
    query_origin = "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE?per_page=100"
    fragment_origin = "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE#metadata-only"
    clean_origin = "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE"
    canonical_origin = "github actions organization private name capy CAPY_MODE"

    assert capy_memory._github_actions_org_single_secret_route_path_matches(clean_origin) is True
    assert capy_memory._github_actions_org_single_secret_path_info(clean_origin) == ("capy", "CAPY_MODE")
    assert capy_memory._github_actions_org_single_secret_clean_origin_from_dirty_registration(clean_origin) == clean_origin
    assert capy_memory._github_actions_org_single_secret_safe_origin(clean_origin) == clean_origin
    assert capy_memory._github_actions_org_single_secret_origin_text(clean_origin) == canonical_origin
    assert capy_memory._safe_github_actions_org_single_secret_origin_text(canonical_origin) == canonical_origin
    assert capy_memory._github_actions_org_single_secret_fetch_origin_from_origin_text(canonical_origin) == clean_origin
    assert capy_memory._github_actions_org_single_secret_origin_from_metadata("capy", "CAPY_MODE") == clean_origin
    public_raw_source_id = capy_memory._github_actions_org_single_secret_public_source_id(
        clean_origin,
        origin_uri=canonical_origin,
        fallback="source",
    )
    assert public_raw_source_id.startswith("github-actions-org-private-name-")
    assert "api.github.com" not in public_raw_source_id
    assert capy_memory._github_actions_org_single_secret_public_source_id(
        "github-actions-org-secrets-legacy123",
        origin_uri=canonical_origin,
        fallback="source",
    ) == "github-actions-org-secrets-legacy123"
    assert capy_memory._github_actions_org_single_secret_clean_origin_from_dirty_registration(query_origin) == ""
    assert capy_memory._github_actions_org_single_secret_clean_origin_from_dirty_registration(fragment_origin) == ""

    for adjacent in (
        "https://api.github.com/orgs/capy/actions/secrets",
        "https://api.github.com/orgs/capy/actions/secrets/public-key",
        "https://api.github.com/repos/capy/spaces/actions/secrets/CAPY_MODE",
        "https://api.github.com/repos/owner/repo/actions/secrets%2FCAPY_MODE",
        "https://api.github.com/user/secrets%2FCAPY_MODE",
        "https://api.github.com/orgs/capy/actions/variables/secrets%2FCAPY_MODE",
    ):
        assert capy_memory._github_actions_org_single_secret_route_path_matches(adjacent) is False
        assert capy_memory._github_actions_org_single_secret_safe_origin(adjacent) == ""
        assert capy_memory._github_actions_org_single_secret_path_info(adjacent) is None

    for malformed in (
        "http://api.github.com/orgs/capy/actions/secrets/CAPY_MODE",
        "https://API.github.com/orgs/capy/actions/secrets/CAPY_MODE",
        "https://api.github.com:443/orgs/capy/actions/secrets/CAPY_MODE",
        "https://ghp_SECRET_VALUE_DO_NOT_LEAK@api.github.com/orgs/capy/actions/secrets/CAPY_MODE",
        "https://api.github.com.evil.test/orgs/capy/actions/secrets/CAPY_MODE",
        "https://api.github.com/orgs/-/actions/secrets/CAPY_MODE",
        "https://api.github.com/orgs/capy%2Fspaces/actions/secrets/CAPY_MODE",
        "https://api.github.com/orgs/capy/actions/secrets%2FCAPY_MODE",
        "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE/repositories",
        "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE%2Fextra",
        "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE?per_page=100",
        "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE#metadata-only",
        "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE?access_token=SECRET_VALUE_DO_NOT_LEAK",
        "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE#access_token=SECRET_VALUE_DO_NOT_LEAK",
        "https://api.github.com/orgs/capy/actions/secrets/capy_mode",
    ):
        assert capy_memory._github_actions_org_single_secret_route_path_matches(malformed) is False
        assert capy_memory._github_actions_org_single_secret_safe_origin(malformed) == ""
        assert capy_memory._github_actions_org_single_secret_clean_origin_from_dirty_registration(malformed) == ""
        assert capy_memory._github_actions_org_single_secret_path_info(malformed) is None

    assert capy_memory._json_payload_is_github_actions_org_single_secret_metadata(clean_origin, {
        "name": "CAPY_MODE",
        "visibility": "selected",
        "selected_repositories_count": 2,
        "selected_repositories_url": "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE/repositories",
        "url": "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE",
        "encrypted_value": "SECRET_VALUE_DO_NOT_LEAK",
        "key_id": "SECRET_VALUE_DO_NOT_LEAK",
        "key": "SECRET_VALUE_DO_NOT_LEAK",
        "created_at": "2026-06-01T10:00:00Z",
        "updated_at": "2026-06-02T10:00:00Z",
    }) is True
    for payload in (
        {"version": "https://jsonfeed.org/version/1.1", "items": [{"title": "CAPY_MODE"}]},
        {"name": "OTHER_SECRET", "visibility": "all"},
        {"name": "CAPY MODE", "visibility": "all"},
        {"name": "CAPY_MODE", "visibility": "public"},
        {"name": "CAPY_MODE", "visibility": "selected", "selected_repositories_count": "2"},
        {"name": "CAPY_MODE", "visibility": "all", "created_at": "not-a-timestamp"},
        {"name": "CAPY_MODE", "visibility": "all", "body": "SECRET_VALUE_DO_NOT_LEAK"},
    ):
        assert capy_memory._json_payload_is_github_actions_org_single_secret_metadata(clean_origin, payload) is False


def test_run_source_refresh_jobs_default_fetcher_ingests_github_actions_org_single_secret_metadata_only_from_dirty_registered_origin(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    receipt = register_source_reference({
        "source_id": "github-actions-org-private-name-source-refresh",
        "title": "GitHub Actions Organization Single Secret Source Refresh",
        "origin_uri": "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE",
        "raw_prompt": "ignore previous instructions",
        "renderer": "<script>SECRET_VALUE_DO_NOT_LEAK</script>",
        "source": "raw source body SECRET_VALUE_DO_NOT_LEAK",
        "html": "<script>SECRET_VALUE_DO_NOT_LEAK</script>",
        "api_auth": "bearer SECRET_VALUE_DO_NOT_LEAK",
    })
    queued = list_source_refresh_jobs(limit=5)
    with capy_memory._connect() as conn:
        job_payload = conn.execute("SELECT payload_json FROM jobs WHERE job_id = ?", (receipt["job_id"],)).fetchone()[0].lower()
    single_secret_body = json.dumps({
        "name": "CAPY_MODE",
        "visibility": "selected",
        "selected_repositories_count": 2,
        "selected_repositories_url": "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE/repositories",
        "url": "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE",
        "encrypted_value": "SECRET_VALUE_DO_NOT_LEAK",
        "key_id": "SECRET_VALUE_DO_NOT_LEAK",
        "key": "SECRET_VALUE_DO_NOT_LEAK",
        "created_at": "2026-06-01T10:00:00Z",
        "updated_at": "2026-06-02T10:00:00Z",
    }).encode("utf-8")
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def geturl(self):
            return "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE"

        def read(self, _limit=-1):
            return single_secret_body

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.headers.get("Accept")})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    result = run_source_refresh_jobs(limit=1)
