    serialized = json.dumps({
        "catalog": catalog,
        "queued": queued,
        "receipt": receipt,
        "relevant": relevant,
        "result": result,
        "search": search,
        "vault": persisted,
    }, sort_keys=True).lower()

    canonical_origin = "github actions organization private name capy CAPY_MODE"
    assert receipt["origin_uri"] == canonical_origin
    assert queued["jobs"][0]["origin_uri"] == canonical_origin
    assert "github actions organization private name capy capy_mode" in job_payload
    assert "fetch_origin_uri" not in job_payload
    assert "api.github.com" not in job_payload
    assert calls == [{
        "url": "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE",
        "timeout": 8,
        "accept": "application/json",
    }]
    assert result["processed"] == 1
    assert result["jobs"][0]["job_id"] == receipt["job_id"]
    assert result["jobs"][0]["status"] == "completed"
    assert search["results"][0]["source_id"] == "github-actions-org-private-name-source-refresh"
    assert search["results"][0]["origin_uri"] == canonical_origin
    auto_fetch = next(connector for connector in catalog["connectors"] if connector["connector_id"] == "auto_fetch")
    catalog_source = next(source for source in auto_fetch["sources"] if source["source_id"] == "github-actions-org-private-name-source-refresh")
    assert catalog_source["origin_uri"] == canonical_origin
    assert catalog_source["display_name"] == "GitHub Actions organization private name capy CAPY_MODE"
    assert f"origin_uri: {canonical_origin}".lower() in persisted
    assert "github actions organization private name capy_mode for capy" in persisted
    assert "private name: capy_mode" in persisted
    assert "visibility: selected" in persisted
    assert "selected repository count: 2" in persisted
    assert "created: 2026-06-01t10:00:00+00:00" in persisted
    assert "updated: 2026-06-02t10:00:00+00:00" in persisted
    for unsafe in (
        "https://",
        "api.github.com",
        "/orgs/capy/actions/secrets/capy_mode",
        "selected_repositories_url",
        "capy_mode/repositories",
        "encrypted_value",
        "key_id",
        "\"key\"",
        "secret_value_do_not_leak",
        "access_token",
        "raw-prompt",
        "ignore previous instructions",
        "raw source body",
        "renderer",
        "html",
        "<script",
        "api_auth",
        "bearer",
        "body",
    ):
        assert unsafe not in persisted
        assert unsafe not in serialized


