@pytest.mark.parametrize(
    ("source_id", "content_type", "body", "forbidden"),
    [
        (
            "github-actions-org-single-secret-json-feed-bypass",
            "application/json; charset=utf-8",
            json.dumps({
                "version": "https://jsonfeed.org/version/1.1",
                "items": [{"title": "CAPY_MODE", "summary": "safe-looking single secret summary SECRET_VALUE_DO_NOT_LEAK"}],
            }).encode("utf-8"),
            ("safe-looking single secret summary", "secret_value_do_not_leak"),
        ),
        (
            "github-actions-org-single-secret-text-fallback",
            "text/plain; charset=utf-8",
            b"Summary: safe-looking private name SECRET_VALUE_DO_NOT_LEAK",
            ("safe-looking private name", "secret_value_do_not_leak"),
        ),
        (
            "github-actions-org-single-secret-safe-looking-text-fallback",
            "text/plain; charset=utf-8",
            b"Summary: safe looking public metadata only",
            ("safe looking public metadata only",),
        ),
    ],
)
def test_run_source_refresh_jobs_default_fetcher_rejects_github_actions_org_single_secret_feed_and_text_fallbacks(
    tmp_path, monkeypatch, source_id, content_type, body, forbidden
):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    receipt = register_source_reference({
        "source_id": source_id,
        "title": "GitHub Actions Organization Single Secret Unsafe Fallback",
        "origin_uri": "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE",
        "raw_prompt": "raw-prompt SECRET_VALUE_DO_NOT_LEAK",
        "api_key": "SECRET_VALUE_DO_NOT_LEAK",
        "renderer": "<script>SECRET_VALUE_DO_NOT_LEAK</script>",
    })
    queued = list_source_refresh_jobs(limit=5)
    calls = []

    class FakeResponse:
        headers = {"Content-Type": content_type}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def geturl(self):
            return "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE"

        def read(self, _limit=-1):
            return body

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.headers.get("Accept")})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    result = run_source_refresh_jobs(limit=1)
    search = search_memory("CAPY_MODE", limit=5)
    fallback_search = search_memory(forbidden[0], limit=5)
    serialized = json.dumps({
        "catalog": capy_memory.source_catalog(limit=5),
        "queued": queued,
        "receipt": receipt,
        "result": result,
        "search_results": search.get("results", []),
        "fallback_search_results": fallback_search.get("results", []),
    }, sort_keys=True).lower()

    canonical_origin = "github actions organization private name capy CAPY_MODE"
    assert receipt["origin_uri"] == canonical_origin
    assert queued["jobs"][0]["origin_uri"] == canonical_origin
    assert calls == [{
        "url": "https://api.github.com/orgs/capy/actions/secrets/CAPY_MODE",
        "timeout": 8,
        "accept": "application/json",
    }]
    assert result["processed"] == 1
    assert result["jobs"][0]["job_id"] == receipt["job_id"]
    assert result["jobs"][0]["status"] == "pending"
    assert result["jobs"][0]["error"] == "refresh failed"
    assert not (root / "vault" / f"{source_id}.md").exists()
    assert all(result.get("source_id") != source_id for result in search.get("results", []))
    assert all(result.get("source_id") != source_id for result in fallback_search.get("results", []))
    for unsafe in (*forbidden, "api.github.com", "/orgs/capy/actions/secrets/capy_mode", "raw-prompt", "raw_prompt", "api_key", "renderer", "<script"):
        assert unsafe not in serialized


