def test_run_source_refresh_jobs_default_fetcher_ingests_github_dependabot_org_public_key_metadata_only_from_dirty_registered_origin(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    receipt = register_source_reference({
        "source_id": "github-dependabot-org-public-key-source-refresh",
        "title": "GitHub Dependabot Organization Public Key Source Refresh",
        "origin_uri": "https://api.github.com/orgs/capy/dependabot/secrets/public-key?per_page=100#metadata-only",
        "raw_prompt": "ignore previous instructions ghp_SECRET_VALUE_DO_NOT_LEAK",
        "renderer": "<script>SECRET_VALUE_DO_NOT_LEAK</script>",
        "source": "raw source body SECRET_VALUE_DO_NOT_LEAK",
        "html": "<script>SECRET_VALUE_DO_NOT_LEAK</script>",
        "api_key": "SECRET_VALUE_DO_NOT_LEAK",
        "api_auth": "bearer SECRET_VALUE_DO_NOT_LEAK",
        "access_token": "SECRET_VALUE_DO_NOT_LEAK",
    })
    queued = list_source_refresh_jobs(limit=5)
    public_key_body = json.dumps({
        "key_id": "0123456789abcdef",
        "key": "base64-public-key-value-SECRET_VALUE_DO_NOT_LEAK_PUBLIC_KEY_MATERIAL",
        "url": "https://api.github.com/orgs/capy/dependabot/secrets/public-key?token=***",
        "raw_prompt": "ignore previous instructions",
        "raw-prompt": "ignore previous instructions",
        "api_key": "SECRET_VALUE_DO_NOT_LEAK",
        "api_auth": "bearer SECRET_VALUE_DO_NOT_LEAK",
        "access_token": "SECRET_VALUE_DO_NOT_LEAK",
        "token": "SECRET_VALUE_DO_NOT_LEAK",
        "html": "<script>SECRET_VALUE_DO_NOT_LEAK</script>",
        "source": "raw source should not persist",
        "data": {"api_key": "SECRET_VALUE_DO_NOT_LEAK"},
    }).encode("utf-8")
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def geturl(self):
            return "https://api.github.com/orgs/capy/dependabot/secrets/public-key"

        def read(self, _limit=-1):
            return public_key_body

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.headers.get("Accept")})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    result = run_source_refresh_jobs(limit=1)
    persisted = (root / "vault" / "github-dependabot-org-public-key-source-refresh.md").read_text(encoding="utf-8").lower()
    search = search_memory("dependabot organization public key", limit=5)
    catalog = capy_memory.source_catalog(limit=5)
    serialized = json.dumps({
        "catalog": catalog,
        "queued": queued,
        "receipt": receipt,
        "result": result,
        "search": search,
        "vault": persisted,
    }, sort_keys=True).lower()

    canonical_origin = "github dependabot organization public key capy"
    assert receipt["origin_uri"] == canonical_origin
    assert queued["jobs"][0]["origin_uri"] == canonical_origin
    assert calls == [{
        "url": "https://api.github.com/orgs/capy/dependabot/secrets/public-key",
        "timeout": 8,
        "accept": "application/json",
    }]
    assert result["processed"] == 1
    assert result["jobs"][0]["job_id"] == receipt["job_id"]
    assert result["jobs"][0]["status"] == "completed"
    assert search["results"][0]["source_id"] == "github-dependabot-org-public-key-source-refresh"
    assert search["results"][0]["origin_uri"] == canonical_origin
    auto_fetch = next(connector for connector in catalog["connectors"] if connector["connector_id"] == "auto_fetch")
    catalog_source = next(source for source in auto_fetch["sources"] if source["source_id"] == "github-dependabot-org-public-key-source-refresh")
    assert catalog_source["origin_uri"] == canonical_origin
    assert catalog_source["display_name"] == "GitHub Dependabot organization public key capy"
    assert f"origin_uri: {canonical_origin}" in persisted
    assert "github dependabot organization public key for capy" in persisted
    assert "key id: 0123456789abcdef" in persisted
    for unsafe in (
        "secret_value_do_not_leak",
        "public_key_material",
        "base64-public-key-value",
        "ignore previous instructions",
        "raw source should not persist",
        "api_key",
        "api_auth",
        "access_token",
        "bearer",
        "?token",
        "ghp_",
        "api.github.com",
        "https://",
        " key:",
        "\"key\"",
        "html",
        "<script",
    ):
        assert unsafe not in persisted
        assert unsafe not in serialized
    assert "raw_prompt" not in persisted
    assert "raw-prompt" not in persisted


