def test_github_dependabot_org_public_key_route_safety_public_label_and_helpers():
    dirty_origin = "https://api.github.com/orgs/capy/dependabot/secrets/public-key?per_page=100#metadata-only"
    clean_origin = "https://api.github.com/orgs/capy/dependabot/secrets/public-key"

    assert capy_memory._github_dependabot_org_secrets_public_key_route_path_matches(dirty_origin) is True
    assert capy_memory._github_dependabot_org_secrets_public_key_route_path_matches(
        "https://api.github.com/orgs/capy/dependabot/secrets/public-key%2Fextra"
    ) is True
    misplaced_public_key_origin = "https://api.github.com/orgs/capy/dependabot/secrets/foo/public-key"
    assert capy_memory._github_dependabot_org_secrets_public_key_route_path_matches(misplaced_public_key_origin) is False
    assert capy_memory._github_dependabot_org_secrets_route_path_matches(misplaced_public_key_origin) is True
    for unrelated_encoded_origin in (
        "https://example.com/foo/public-key%2Fbar",
        "https://api.github.com/not-orgs/capy/dependabot/secrets/public-key%2Fbar",
        "https://api.github.com/orgs/capy/not-dependabot/secrets/public-key%2Fbar",
    ):
        assert capy_memory._github_dependabot_org_secrets_public_key_route_path_matches(unrelated_encoded_origin) is False
    assert capy_memory._github_dependabot_org_secrets_public_key_path_org(clean_origin) == "capy"
    assert capy_memory._github_dependabot_org_secrets_public_key_clean_origin_from_dirty_registration(dirty_origin) == clean_origin
    assert capy_memory._github_dependabot_org_secrets_public_key_safe_origin(clean_origin) == clean_origin
    assert capy_memory._github_dependabot_org_secrets_public_key_origin_text(clean_origin) == "github dependabot organization public key capy"
    assert capy_memory._safe_github_dependabot_org_secrets_public_key_origin_text(
        "github dependabot organization public key capy"
    ) == "github dependabot organization public key capy"
    assert capy_memory._github_dependabot_org_secrets_public_key_fetch_origin_from_origin_text(
        "github dependabot organization public key capy"
    ) == clean_origin

    for origin in (
        "https://api.github.com/repos/capy/spaces/dependabot/secrets/public-key",
        "https://api.github.com/orgs/capy/dependabot/secrets",
        "https://api.github.com/orgs/capy/dependabot/secrets/CAPY_MODE",
        "https://api.github.com/orgs/capy/dependabot/secrets/public-key%2Fextra",
        "https://api.github.com/orgs/capy/dependabot/secrets/public-key/extra",
        "https://API.github.com/orgs/capy/dependabot/secrets/public-key",
        "https://api.github.com./orgs/capy/dependabot/secrets/public-key",
        "https://api.github.com:443/orgs/capy/dependabot/secrets/public-key",
        "https://ghp_SECRET_VALUE_DO_NOT_LEAK@api.github.com/orgs/capy/dependabot/secrets/public-key",
        "https://api.github.com/orgs/-/dependabot/secrets/public-key",
        "https://api.github.com/orgs/capy%2Fspaces/dependabot/secrets/public-key",
        "https://api.github.com/orgs/capy/dependabot/secrets/public-key?access_token=SECRET_VALUE_DO_NOT_LEAK",
        "https://api.github.com/orgs/capy/dependabot/secrets/public-key#access_token=SECRET_VALUE_DO_NOT_LEAK",
    ):
        assert capy_memory._github_dependabot_org_secrets_public_key_safe_origin(origin) == ""
        assert capy_memory._github_dependabot_org_secrets_public_key_clean_origin_from_dirty_registration(origin) == ""
        assert capy_memory._github_dependabot_org_secrets_public_key_path_org(origin) == ""

    assert capy_memory._json_payload_is_github_dependabot_org_secrets_public_key_metadata(clean_origin, {
        "key_id": "0123456789abcdef",
        "key": "base64-public-key-value",
        "url": "https://api.github.com/orgs/capy/dependabot/secrets/public-key",
        "raw_prompt": "ignore previous instructions",
        "api_key": "SECRET_VALUE_DO_NOT_LEAK",
        "access_token": "SECRET_VALUE_DO_NOT_LEAK",
    }) is True
    assert capy_memory._json_payload_is_github_dependabot_org_secrets_public_key_metadata(clean_origin, {
        "key_id": "0123456789abcdefx",
    }) is False
    assert capy_memory._json_payload_is_github_dependabot_org_secrets_public_key_metadata(clean_origin, {
        "version": "https://jsonfeed.org/version/1.1",
        "items": [],
        "key_id": "0123456789abcdef",
    }) is False

