    assert result["jobs"][0]["status"] == "completed"
    assert search["results"][0]["source_id"] == "github-actions-single-variable-source-refresh"
    assert search["results"][0]["origin_uri"] == canonical_origin
    auto_fetch = next(connector for connector in catalog["connectors"] if connector["connector_id"] == "auto_fetch")
    catalog_source = next(source for source in auto_fetch["sources"] if source["source_id"] == "github-actions-single-variable-source-refresh")
    assert catalog_source["origin_uri"] == canonical_origin
    assert f"origin_uri: {canonical_origin.lower()}" in persisted
    assert "github actions repository variable for capy/spaces" in persisted
    assert "variable: capy_mode" in persisted
    assert "created: 2026-06-01t10:00:00+00:00" in persisted
    assert "updated: 2026-06-02t10:00:00+00:00" in persisted
    for unsafe in (
        "secret_value_do_not_leak",
        "raw variable value",
        "bearer placeholder",
        "html_url",
        "github.com/capy/spaces/settings",
        "value",
        "url",
        "api_key",
        "api_auth",
        "access_token",
        "ignore previous instructions",
        "renderer",
        "source body",
        "html",
        "<script",
        "?token",
        "ghp_",
        "raw-prompt",
    ):
        assert unsafe not in persisted
        assert unsafe not in serialized
    assert "raw_prompt" not in persisted


