def test_legacy_github_actions_selected_actions_exact_raw_route_public_surfaces_use_metadata_label(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    init_memory_tree()
    source_id = "legacy-github-actions-selected-actions-exact"
    safe_label = "github actions selected actions capy/spaces"
    legacy_origin_uri = (
        "https://api.github.com/repos/capy/spaces/actions/permissions/selected-actions"
        "?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt"
    )
    legacy_title = "https://api.github.com/repos/capy/spaces/actions/permissions/selected-actions"
    now = "2026-06-06T00:00:00+00:00"
    payload = {
        "source_id": source_id,
        "origin_uri": legacy_origin_uri,
        "display_name": legacy_title,
        "title": legacy_title,
    }

    with sqlite3.connect(memory_tree_db_path()) as conn:
        conn.execute(
            """
            INSERT INTO sources (
                source_id, source_type, display_name, origin_uri, origin_kind,
                freshness_status, last_checked_at, created_at, updated_at
            )
            VALUES (?, 'source_registry', ?, ?, 'auto_fetch', 'stale', ?, ?, ?)
            """,
            (source_id, legacy_title, legacy_origin_uri, now, now, now),
        )
        conn.execute(
            """
            INSERT INTO chunks (
                chunk_id, source_id, source_ref, content_path, summary, approx_tokens,
                lifecycle_status, redaction_status, created_at, updated_at
            )
            VALUES (?, ?, ?, ?, 'selected actions searchable metadata only', 5, 'admitted', 'metadata_only', ?, ?)
            """,
            (
                f"{source_id}-chunk",
                source_id,
                legacy_origin_uri,
                str(root / "vault" / f"{source_id}.md"),
                now,
                now,
            ),
        )
        conn.execute(
            """
            INSERT INTO jobs (job_id, kind, dedupe_key, payload_json, status, attempts, created_at, updated_at)
            VALUES ('cmt-job-legacy-github-actions-selected-actions-exact', 'source.refresh', ?, ?, 'pending', 0, ?, ?)
            """,
            (source_id, json.dumps(payload, sort_keys=True, separators=(",", ":")), now, now),
        )

