    search_hit = next(result for result in search["results"] if result["source_id"] == source_id)
    serialized = json.dumps({"catalog": catalog, "jobs": jobs, "search": search}, sort_keys=True).lower()

    assert catalog_source["origin_uri"] == safe_label
    assert catalog_source["display_name"] == safe_label
    assert queued_job["origin_uri"] == safe_label
    assert search_hit["origin_uri"] == safe_label
    assert search_hit["title"] == safe_label
