def _insert_selected_actions_public_surface_fixture(
    root,
    *,
    source_id: str,
    chunk_id: str | None = None,
    origin_uri: str,
    display_name: str,
    source_ref: str | None = None,
    payload_title: str | None = None,
    summary: str = "selected actions public surface metadata only",
) -> None:
    now = "2026-06-06T00:00:00+00:00"
    payload = {
        "source_id": source_id,
        "origin_uri": origin_uri,
        "display_name": display_name,
        "title": payload_title if payload_title is not None else display_name,
    }
    with sqlite3.connect(memory_tree_db_path()) as conn:
        conn.execute(
            """
            INSERT INTO sources (
                source_id, source_type, display_name, origin_uri, origin_kind,
                freshness_status, last_checked_at, created_at, updated_at
            )
            VALUES (?, 'source_registry', ?, ?, 'auto_fetch', 'stale', ?, ?, ?)
            """,
            (source_id, display_name, origin_uri, now, now, now),
        )
        conn.execute(
            """
            INSERT INTO chunks (
                chunk_id, source_id, source_ref, content_path, summary, approx_tokens,
                lifecycle_status, redaction_status, created_at, updated_at
            )
            VALUES (?, ?, ?, ?, ?, 5, 'admitted', 'metadata_only', ?, ?)
            """,
            (
                chunk_id or f"{source_id}-chunk",
                source_id,
                source_ref if source_ref is not None else origin_uri,
                str(root / "vault" / f"{source_id}.md"),
                summary,
                now,
                now,
            ),
        )
        conn.execute(
            """
            INSERT INTO jobs (job_id, kind, dedupe_key, payload_json, status, attempts, created_at, updated_at)
            VALUES (?, 'source.refresh', ?, ?, 'pending', 0, ?, ?)
            """,
            (
                f"cmt-job-{source_id}",
                source_id,
                json.dumps(payload, sort_keys=True, separators=(",", ":")),
                now,
                now,
            ),
        )


def _selected_actions_public_surface_results(source_id: str, query: str) -> tuple[dict, dict, dict]:
    catalog = capy_memory.source_catalog(limit=10)
    jobs = list_source_refresh_jobs(limit=10)
    search = search_memory(query, limit=10)
    catalog_source = next(
        source
        for connector in catalog["connectors"]
        for source in connector["sources"]
        if source["source_id"] == source_id
    )
    queued_job = next(job for job in jobs["jobs"] if job["source_id"] == source_id)
    search_hit = next(result for result in search["results"] if result["source_id"] == source_id)
    return catalog_source, queued_job, search_hit


@pytest.mark.parametrize(
    "unsafe_snippet",
    [
        "selected-actions searchable raw-prompt benign instructions",
        "selected-actions searchable raw_prompt benign instructions",
        "selected-actions searchable data: benign",
        "selected-actions searchable html: benign",
        "selected-actions searchable source: benign",
        "selected-actions searchable script: benign",
        "selected-actions searchable code: benign",
        'selected-actions searchable {"data": "benign"}',
        'selected-actions searchable {"html": "benign"}',
        'selected-actions searchable {"source": "benign"}',
        'selected-actions searchable {"script": "benign"}',
        'selected-actions searchable {"code": "benign"}',
        "selected-actions searchable {'data': 'benign'}",
        "selected-actions searchable {'html': 'benign'}",
        "selected-actions searchable {'source': 'benign'}",
        "selected-actions searchable {'script': 'benign'}",
        "selected-actions searchable {'code': 'benign'}",
    ],
)
def test_legacy_github_actions_selected_actions_search_snippet_unsafe_field_markers_fail_closed(
    tmp_path, monkeypatch, unsafe_snippet
):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    init_memory_tree()
    source_id = "legacy-github-actions-selected-actions-unsafe-snippet"
    safe_label = "github actions selected actions capy/spaces"

    _insert_selected_actions_public_surface_fixture(
        root,
        source_id=source_id,
        origin_uri=safe_label,
        display_name=safe_label,
        payload_title=safe_label,
        summary=unsafe_snippet,
    )

    _catalog_source, _queued_job, search_hit = _selected_actions_public_surface_results(
        source_id,
        "selected-actions searchable",
    )

    assert search_hit["origin_uri"] == safe_label
    assert search_hit["snippet"] == safe_label
    assert unsafe_snippet.lower() not in search_hit["snippet"].lower()


