def test_queue_due_source_refresh_jobs_selected_actions_legacy_raw_origin_uses_public_label(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    init_memory_tree()
    source_id = "github-selected-actions-due-legacy-raw-origin"
    raw_origin = (
        "https://api.github.com/repos/capy/spaces/actions/permissions/selected-actions"
        "?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt"
    )
    clean_fetch_origin = "https://api.github.com/repos/capy/spaces/actions/permissions/selected-actions"
    public_origin = "github actions selected actions capy/spaces"
    now = "2026-06-06T00:00:00+00:00"
    payload = {
        "source_id": source_id,
        "origin_uri": raw_origin,
        "refresh_interval_seconds": 60,
    }

    with sqlite3.connect(memory_tree_db_path()) as conn:
        conn.execute(
            """
            INSERT INTO sources (
                source_id, source_type, display_name, origin_uri, origin_kind,
                freshness_status, last_checked_at, created_at, updated_at
            )
            VALUES (?, 'source_registry', 'GitHub Selected Actions Due Legacy Raw Origin',
                    ?, 'auto_fetch', 'ok', ?, ?, ?)
            """,
            (source_id, raw_origin, now, now, now),
        )
        conn.execute(
            """
            INSERT INTO jobs (job_id, kind, dedupe_key, payload_json, status, attempts, created_at, updated_at)
            VALUES ('cmt-job-selected-actions-due-legacy-raw-origin', 'source.refresh', ?, ?, 'completed', 1, ?, ?)
            """,
            (source_id, json.dumps(payload, sort_keys=True, separators=(",", ":")), now, now),
        )

    queued = queue_due_source_refresh_jobs(limit=1, now="2026-06-06T00:02:00+00:00")
    with sqlite3.connect(memory_tree_db_path()) as conn:
        queued_payload = json.loads(conn.execute(
            "SELECT payload_json FROM jobs WHERE job_id = 'cmt-job-selected-actions-due-legacy-raw-origin'"
        ).fetchone()[0])
    public_serialized = json.dumps(queued, sort_keys=True).lower()

    assert queued["queued"] == 1
    assert queued["jobs"][0]["source_id"] == source_id
    assert queued["jobs"][0]["origin_uri"] == public_origin
    assert queued_payload["origin_uri"] == public_origin
    assert queued_payload["fetch_origin_uri"] == clean_fetch_origin
    assert "api.github.com/repos/capy/spaces/actions/permissions/selected-actions" not in public_serialized
    for unsafe in ("access_token", "raw-prompt", "secret_value_do_not_leak"):
        assert unsafe not in public_serialized


