def test_search_public_hit_preserves_non_selected_source_id_text(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    init_memory_tree()
    now = "2026-06-06T00:00:00+00:00"
    rows = [
        ("ordinary docs", "nonselected ordinary public hit searchable"),
        ("api-key-docs", "nonselected product docs public hit searchable"),
    ]
    with sqlite3.connect(memory_tree_db_path()) as conn:
        for idx, (source_id, summary) in enumerate(rows):
            conn.execute(
                """
                INSERT INTO sources (
                    source_id, source_type, display_name, origin_uri, origin_kind,
                    freshness_status, last_checked_at, created_at, updated_at
                )
                VALUES (?, 'source_registry', ?, ?, 'local', 'ok', ?, ?, ?)
                """,
                (source_id, f"Title {idx}", f"capy-memory://nonselected-{idx}", now, now, now),
            )
            conn.execute(
                """
                INSERT INTO chunks (
                    chunk_id, source_id, source_ref, content_path, summary, approx_tokens,
                    lifecycle_status, redaction_status, created_at, updated_at
                )
                VALUES (?, ?, ?, ?, ?, 5, 'admitted', 'metadata_only', ?, ?)
                """,
                (
                    f"nonselected-public-hit-{idx}",
                    source_id,
                    f"capy-memory://nonselected-{idx}",
                    str(root / "vault" / f"nonselected-public-hit-{idx}.md"),
                    summary,
                    now,
                    now,
                ),
            )

    ordinary = search_memory("nonselected ordinary public hit", limit=5)["results"][0]
    api_key_named = search_memory("nonselected product docs public hit", limit=5)["results"][0]

    assert ordinary["source_id"] == "ordinary docs"
    assert api_key_named["source_id"] == "api-key-docs"


