def test_legacy_github_actions_selected_actions_route_abuse_public_surfaces_fail_closed(
    tmp_path, monkeypatch, source_id, legacy_origin_uri, legacy_title, forbidden
):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    init_memory_tree()
    now = "2026-06-06T00:00:00+00:00"
    payload = {"source_id": source_id, "origin_uri": legacy_origin_uri, "title": legacy_title}

    with sqlite3.connect(memory_tree_db_path()) as conn:
        conn.execute(
            """
            INSERT INTO sources (
                source_id, source_type, display_name, origin_uri, origin_kind,
                freshness_status, last_checked_at, created_at, updated_at
            )
            VALUES (?, 'source_registry', ?, ?, 'auto_fetch', 'stale', ?, ?, ?)
            """,
            (source_id, legacy_title, legacy_origin_uri, now, now, now),
        )
        conn.execute(
            """
            INSERT INTO chunks (
                chunk_id, source_id, source_ref, content_path, summary, approx_tokens,
                lifecycle_status, redaction_status, created_at, updated_at
            )
            VALUES (?, ?, ?, ?, 'selected actions hostile searchable metadata only', 6, 'admitted', 'metadata_only', ?, ?)
            """,
            (
                f"{source_id}-chunk",
                source_id,
                legacy_origin_uri,
                str(root / "vault" / f"{source_id}.md"),
                now,
                now,
            ),
        )
        conn.execute(
            """
            INSERT INTO jobs (job_id, kind, dedupe_key, payload_json, status, attempts, created_at, updated_at)
            VALUES (?, 'source.refresh', ?, ?, 'pending', 0, ?, ?)
            """,
            (
                f"cmt-job-{source_id}",
                source_id,
                json.dumps(payload, sort_keys=True, separators=(",", ":")),
                now,
                now,
            ),
        )

    catalog = capy_memory.source_catalog(limit=10)
    jobs = list_source_refresh_jobs(limit=10)
    search = search_memory("hostile searchable", limit=10)
    catalog_source = next(
        source
        for connector in catalog["connectors"]
        for source in connector["sources"]
        if source["source_id"] == source_id
    )
    queued_job = next(job for job in jobs["jobs"] if job["source_id"] == source_id)
    search_hit = next(result for result in search["results"] if result["source_id"] == source_id)
    serialized = json.dumps({"catalog": catalog, "jobs": jobs, "search": search}, sort_keys=True).lower()

    assert catalog_source["origin_uri"] == f"capy-memory://{source_id}"
    assert queued_job["origin_uri"] == f"capy-memory://{source_id}"
    assert search_hit["origin_uri"] == f"capy-memory://{source_id}"
    assert catalog_source["display_name"] == source_id
    assert search_hit["title"] == source_id
    for unsafe in (
        forbidden,
        "api.github.com/repos/capy/spaces/actions/permissions/selected-actions",
        "access_token",
        "raw-prompt",
        "api_key",
        "secret_value_do_not_leak",
        "<script",
        "raw hostile prompt text",
    ):
        assert unsafe not in serialized


