def test_github_actions_selected_actions_due_requeue_preserves_hidden_fetch_origin_and_fetches(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    source_id = "selected-safe"
    safe_label = "github actions selected actions capy/spaces"
    fetch_origin = "https://api.github.com/repos/capy/spaces/actions/permissions/selected-actions"
    origin_uri = f"{fetch_origin}?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt"
    receipt = register_source_reference({
        "source_id": source_id,
        "title": "GitHub Actions Selected Actions Due Requeue",
        "origin_uri": origin_uri,
        "refresh_interval_seconds": 3600,
    })
    calls = []

    def fake_fetcher(*, source_id, origin_uri):
        calls.append({"source_id": source_id, "origin_uri": origin_uri})
        return {
            "metadata_only": True,
            "title": "Selected actions metadata",
            "summary": "GitHub-owned actions allowed; verified actions allowed; patterns: actions/*.",
        }

    first_run = run_source_refresh_jobs(limit=1, fetcher=fake_fetcher, queue_due=False)
    assert first_run["processed"] == 1
    assert first_run["jobs"][0]["status"] == "completed"
    assert calls == [{"source_id": source_id, "origin_uri": fetch_origin}]

    stale_at = "2026-06-06T00:00:00+00:00"
    with sqlite3.connect(memory_tree_db_path()) as conn:
        conn.execute(
            """
            UPDATE sources
            SET freshness_status = 'stale', last_checked_at = ?, updated_at = ?
            WHERE source_id = ?
            """,
            (stale_at, stale_at, source_id),
        )
        conn.execute(
            """
            UPDATE jobs
            SET status = 'completed', updated_at = ?
            WHERE job_id = ?
            """,
            (stale_at, receipt["job_id"]),
        )

    requeued = queue_due_source_refresh_jobs(limit=1, now="2026-06-06T02:00:00+00:00")
    jobs = list_source_refresh_jobs(limit=5)
    with sqlite3.connect(memory_tree_db_path()) as conn:
        requeued_payload = json.loads(conn.execute(
            "SELECT payload_json FROM jobs WHERE job_id = ?",
            (receipt["job_id"],),
        ).fetchone()[0])
    serialized_public = json.dumps({"requeued": requeued, "jobs": jobs}, sort_keys=True).lower()

    assert requeued["queued"] == 1
    assert requeued["jobs"][0]["source_id"] == source_id
    assert requeued["jobs"][0]["origin_uri"] == safe_label
    assert jobs["jobs"][0]["origin_uri"] == safe_label
    assert requeued_payload == {
        "fetch_origin_uri": fetch_origin,
        "origin_uri": safe_label,
        "refresh_interval_seconds": 3600,
        "source_id": source_id,
    }
    assert safe_label in serialized_public
    for unsafe in (
        "api.github.com/repos/capy/spaces/actions/permissions/selected-actions",
        "access_token",
        "raw-prompt",
        "secret_value_do_not_leak",
    ):
        assert unsafe not in serialized_public

    calls.clear()
    second_run = run_source_refresh_jobs(limit=1, fetcher=fake_fetcher, queue_due=False)
    serialized_second_public = json.dumps(second_run, sort_keys=True).lower()

    assert calls == [{"source_id": source_id, "origin_uri": fetch_origin}]
    assert second_run["processed"] == 1
    assert second_run["jobs"][0]["status"] == "completed"
    assert second_run["jobs"][0]["source_id"] == source_id
    for unsafe in (
        "api.github.com/repos/capy/spaces/actions/permissions/selected-actions",
        "access_token",
        "raw-prompt",
        "secret_value_do_not_leak",
    ):
        assert unsafe not in serialized_second_public


