    assert result["jobs"][0]["job_id"] == receipt["job_id"]
    assert result["jobs"][0]["status"] == "completed"
    assert calls == [{
        "url": canonical_origin,
        "timeout": 8,
        "accept": "application/json",
    }]
    assert "github actions organization permissions for capy" in persisted
    assert "enabled repositories: selected" in persisted
    assert "allowed actions: selected" in persisted
    assert search_memory("actions organization permissions", limit=5)["results"][0]["source_id"] == "github-actions-org-permissions-source-refresh"
    for unsafe in (
        "api.github.com",
        "/orgs/capy/actions/permissions",
        "secret_value_do_not_leak",
        "bearer placeholder",
        "selected_actions_url",
        "api_auth",
        "api_key",
        "access_token",
        "ignore previous instructions",
        "raw source should not persist",
        "<script",
        "?token",
        "ghp_",
        "html",
    ):
        assert unsafe not in persisted
        assert unsafe not in serialized
    assert "raw_prompt" not in persisted


