def test_run_source_refresh_jobs_default_fetcher_rejects_github_environment_secrets_public_key_final_url_route_drift(
    tmp_path, monkeypatch, final_url, drift_fragments
):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    origin_uri = "https://api.github.com/repos/owner/repo/environments/Prod%20West/secrets/public-key"
    receipt = register_source_reference({
        "source_id": "github-environment-public-key-final-url-drift",
        "title": "GitHub Environment Secrets Public Key Final URL Drift",
        "origin_uri": origin_uri,
    })
    public_key_body = json.dumps({
        "key_id": "568250167242549743",
        "key": "SECRET_VALUE_DO_NOT_LEAK_PUBLIC_KEY_MATERIAL",
        "api_auth": "API_AUTH_FIXTURE_DO_NOT_PERSIST",
        "api_key": "SECRET_VALUE_DO_NOT_LEAK",
        "raw_prompt": "PROMPT_FIXTURE_DO_NOT_PERSIST",
        "renderer": "RENDERER_FIXTURE_DO_NOT_PERSIST",
        "source": "SOURCE_FIXTURE_DO_NOT_PERSIST",
        "html": "<html>HTML_FIXTURE_DO_NOT_PERSIST</html>",
        "script": "<script>SCRIPT_FIXTURE_DO_NOT_PERSIST</script>",
        "token": "TOKEN_FIXTURE_DO_NOT_PERSIST",
    }).encode("utf-8")
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def geturl(self):
            return final_url

        def read(self, _limit=-1):
            return public_key_body

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.headers.get("Accept")})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    result = run_source_refresh_jobs(limit=1)
    search = search_memory("environment public key", limit=5)
    serialized = json.dumps({
        "receipt": receipt,
        "jobs": list_source_refresh_jobs(limit=5),
        "catalog": capy_memory.source_catalog(limit=5),
        "result": result,
        "search": search,
    }, sort_keys=True).lower()
    text_artifacts = "\n".join(
        path.read_text(encoding="utf-8")
        for path in root.rglob("*")
        if path.is_file() and path.suffix.lower() in {".json", ".md", ".txt"}
    ).lower()

    assert result["processed"] == 1
    assert result["jobs"][0]["job_id"] == receipt["job_id"]
    assert result["jobs"][0]["status"] == "pending"
    assert result["jobs"][0]["error"] == "refresh failed"
    assert calls == [{"url": origin_uri, "timeout": 8, "accept": "application/json"}]
    assert not (root / "vault" / "github-environment-public-key-final-url-drift.md").exists()
    assert search["results"] == []
    unsafe_fragments = (
        "secret_value_do_not_leak",
        "public_key_material",
        "api_auth_fixture_do_not_persist",
        "api_key",
        "prompt_fixture_do_not_persist",
        "renderer_fixture_do_not_persist",
        "source_fixture_do_not_persist",
        "html_fixture_do_not_persist",
        "script_fixture_do_not_persist",
        "token_fixture_do_not_persist",
        "drifted_final_url_token_do_not_persist",
        "raw_prompt",
        "raw-prompt",
        final_url.lower(),
        *drift_fragments,
    )
    for unsafe in unsafe_fragments:
        assert unsafe not in serialized
        assert unsafe not in text_artifacts


