def test_run_source_refresh_jobs_default_fetcher_rejects_github_environment_deployment_branch_policy_final_url_drift_before_body_read_relevant_memory_empty(
    tmp_path,
    monkeypatch,
    source_id,
    title,
    origin_uri,
    canonical_url,
    drifted_final_url,
    search_query,
):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    receipt = register_source_reference({
        "source_id": source_id,
        "title": title,
        "origin_uri": origin_uri,
    })
    calls = []
    read_calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def geturl(self):
            return drifted_final_url

        def read(self, _limit=-1):
            read_calls.append(_limit)
            raise AssertionError(
                "deployment branch policy drift body sentinel renderer raw prompt source html script API-auth SECRET_VALUE_DO_NOT_LEAK"
            )

    def fake_refresh_open(request, *, timeout):
        calls.append({
            "url": request.full_url,
            "timeout": timeout,
            "accept": request.headers.get("Accept"),
        })
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    result = run_source_refresh_jobs(limit=1)
    jobs = list_source_refresh_jobs(limit=5)
    catalog = capy_memory.source_catalog(limit=5)
    search = search_memory(search_query, limit=5)
    relevant = relevant_memory_for_space("environment-deployment-branch-policy-drift-space", limit=5)
    serialized = json.dumps({
        "catalog": catalog,
        "jobs": jobs,
        "relevant": relevant,
        "result": result,
        "search": search,
    }, sort_keys=True).lower()
    text_artifacts = "\n".join(
        path.read_text(encoding="utf-8")
        for path in root.rglob("*")
        if path.is_file() and path.suffix.lower() in {".json", ".md", ".txt"}
    ).lower()

    assert calls == [{"url": canonical_url, "timeout": 8, "accept": "application/json"}]
    assert read_calls == []
    assert result["processed"] == 1
    assert result["jobs"][0]["job_id"] == receipt["job_id"]
    assert result["jobs"][0]["status"] == "pending"
    assert result["jobs"][0]["error"] == "refresh failed"
    assert not any(job.get("status") == "completed" for job in result["jobs"])
    assert not (root / "vault" / f"{source_id}.md").exists()
    assert search["results"] == []
    assert relevant["results"] == []
    assert drifted_final_url.lower() not in serialized
    assert drifted_final_url.lower() not in text_artifacts
    for unsafe in (
        "deployment branch policy drift body sentinel",
        "secret_value_do_not_leak",
        "ghp_secret_value_do_not_leak",
        "access_token",
        "token=",
        "raw-prompt",
        "raw prompt",
        "raw_prompt",
        "renderer",
        '\"source\":',
        '\"html\":',
        '\"script\":',
        '\"data\":',
        "api-auth",
        "api_auth",
        "<script",
        "api.github.com/repos/evil",
        "api.github.com/repos/capy/evil",
        "production%20west",
        "deployment-branch-policies/999",
    ):
        assert unsafe not in serialized
        assert unsafe not in text_artifacts


