def test_run_source_refresh_jobs_default_fetcher_rejects_github_security_advisories_final_url_drift_before_body_read_relevant_memory_empty(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    source_ids = [
        "github-security-advisories-final-url-query-drift",
        "github-security-advisories-final-url-userinfo-drift",
    ]
    for source_id in source_ids:
        register_source_reference({
            "source_id": source_id,
            "title": "GitHub Security Advisories Final URL Drift",
            "origin_uri": "https://api.github.com/repos/capy/spaces/security-advisories?access_token=***#raw-prompt",
        })
    hostile_body = json.dumps([{
        "ghsa_id": "GHSA-drif-tbad-body",
        "cve_id": "CVE-2026-55555",
        "severity": "high",
        "state": "published",
        "created_at": "2026-06-01T10:00:00Z",
        "updated_at": "2026-06-02T11:00:00Z",
        "published_at": "2026-06-03T12:00:00Z",
        "withdrawn_at": None,
        "summary": "Final URL drift advisory summary must not persist.",
        "description": "Final URL drift advisory body sentinel must not persist.",
        "vulnerabilities": [{"package": {"name": "final-url-drift-package"}}],
        "renderer": "<script>render()</script>",
        "source": "raw final URL drift source should not persist",
        "html": "<script>steal()</script>",
        "script": "alert('SECRET_VALUE_DO_NOT_LEAK')",
        "data": {"api-auth": "ghp_SECRET_VALUE_DO_NOT_LEAK"},
        "api_key": "SECRET_VALUE_DO_NOT_LEAK",
    }]).encode("utf-8")
    final_urls = [
        "https://api.github.com/repos/capy/spaces/security-advisories?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt",
        "https://ghp_SECRET_VALUE_DO_NOT_LEAK@api.github.com/repos/capy/spaces/security-advisories?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt",
    ]
    calls = []
    read_calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __init__(self, final_url):
            self._final_url = final_url

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def geturl(self):
            return self._final_url

        def read(self, _limit=-1):
            read_calls.append(_limit)
            return hostile_body

    def fake_refresh_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.headers.get("Accept")})
        return FakeResponse(final_urls[len(calls) - 1])

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_refresh_open)

    result = run_source_refresh_jobs(limit=2)
    catalog = source_catalog(limit=5)
    search = search_memory("final-url-drift-package", limit=5)
    relevant = relevant_memory_for_space("security-advisories-drift-space", limit=5)
    serialized = json.dumps({
        "result": result,
        "catalog": catalog,
        "search_results": search["results"],
        "relevant": relevant,
    }, sort_keys=True).lower()

    assert calls == [
        {
            "url": "https://api.github.com/repos/capy/spaces/security-advisories",
            "timeout": 8,
            "accept": "application/json",
        },
        {
            "url": "https://api.github.com/repos/capy/spaces/security-advisories",
            "timeout": 8,
            "accept": "application/json",
        },
    ]
    assert read_calls == []
    assert result["processed"] == 2
    assert {job["status"] for job in result["jobs"]} == {"pending"}
    assert {job["error"] for job in result["jobs"]} <= {"refresh fetcher disabled", "refresh failed"}
    for source_id in source_ids:
        assert not (root / "vault" / f"{source_id}.md").exists()
    assert search["results"] == []
    assert relevant["results"] == []
    for unsafe in (
        "https://api.github.com/repos/capy/spaces/security-advisories",
        "api.github.com/repos/capy/spaces/security-advisories",
        "ghp_",
        "secret_value_do_not_leak",
        "access_token",
        "raw-prompt",
        "raw prompt",
        "ghsa-drif-tbad-body",
        "cve-2026-55555",
        "final url drift advisory",
        "final-url-drift-package",
        "raw final url drift source",
        "vulnerabilities",
        "description",
        "renderer",
        "html",
        "<script",
        "script",
        '"source":',
        "api-auth",
        "api_key",
        "authorization",
        "token",
    ):
        assert unsafe not in serialized


