def test_run_source_refresh_jobs_default_fetcher_rejects_github_actions_org_runner_labels_route_abuse_before_fetch(
    tmp_path, monkeypatch, source_id, origin_uri
):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com,api.github.com.evil.test")
    init_memory_tree()
    register_source_reference({
        "source_id": source_id,
        "title": "GitHub Actions Org Runner Labels Route Abuse",
        "origin_uri": origin_uri,
    })
    calls = []

    def fake_open(*_args, **_kwargs):
        calls.append("called")
        raise AssertionError("malformed actions organization runner labels route must fail before fetch")

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_open)

    result = run_source_refresh_jobs(limit=1)
    serialized = json.dumps(result, sort_keys=True).lower()

    assert calls == []
    assert result["processed"] == 1
    assert result["jobs"][0]["status"] == "pending"
    assert result["jobs"][0]["error"] == "refresh failed"
    assert not (root / "vault" / f"{source_id}.md").exists()
    assert "secret_value_do_not_leak" not in serialized
    assert "api.github.com.evil.test" not in serialized
    assert "access_token" not in serialized
    assert "raw-prompt" not in serialized


