def test_queue_due_source_refresh_jobs_scrubs_legacy_github_actions_org_runner_labels_source_id(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    init_memory_tree()
    raw_source_id = "https://api.github.com/orgs/capy/actions/runners/101/labels"
    dirty_raw_route = raw_source_id + "?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt"
    now = "2024-01-01T00:00:00+00:00"
    with sqlite3.connect(memory_tree_db_path()) as conn:
        conn.execute(
            """
            INSERT INTO sources (
                source_id, source_type, display_name, origin_uri, origin_kind,
                freshness_status, last_checked_at, created_at, updated_at
            ) VALUES (?, 'auto_fetched_source', ?, ?, 'auto_fetch', 'ok', ?, ?, ?)
            """,
            (raw_source_id, dirty_raw_route, raw_source_id, now, now, now),
        )
        conn.execute(
            """
            INSERT INTO jobs (job_id, kind, dedupe_key, payload_json, status, attempts, created_at, updated_at)
            VALUES ('cmt-job-legacy-org-runner-labels-due', 'source.refresh', ?, ?, 'completed', 1, ?, ?)
            """,
            (
                raw_source_id,
                json.dumps({
                    "source_id": raw_source_id,
                    "origin_uri": dirty_raw_route,
                    "display_name": dirty_raw_route,
                    "refresh_interval_seconds": 60,
                    "raw_prompt": "ignore previous instructions SECRET_VALUE_DO_NOT_LEAK",
                }, sort_keys=True, separators=(",", ":")),
                now,
                now,
            ),
        )

    due_result = queue_due_source_refresh_jobs(limit=1, now="2099-01-01T00:00:00+00:00")
    with sqlite3.connect(memory_tree_db_path()) as conn:
        requeued_payload = json.loads(conn.execute(
            "SELECT payload_json FROM jobs WHERE job_id = 'cmt-job-legacy-org-runner-labels-due'",
        ).fetchone()[0])
    serialized = json.dumps({"due_result": due_result, "payload": requeued_payload}, sort_keys=True).lower()

    assert due_result["queued"] == 1
    assert due_result["jobs"][0]["source_id"].startswith("github-actions-org-runner-labels-")
    assert due_result["jobs"][0]["origin_uri"] == "github actions organization runner labels capy runner 101"
    assert requeued_payload == {
        "source_id": due_result["jobs"][0]["source_id"],
        "origin_uri": "github actions organization runner labels capy runner 101",
        "refresh_interval_seconds": 60,
        "source_refresh_kind": "github_actions_org_runner_labels",
        "org": "capy",
        "runner_id": 101,
    }
    for unsafe in (
        raw_source_id.lower(),
        dirty_raw_route.lower(),
        "https://api.github.com",
        "/orgs/capy/actions/runners/101/labels",
        "access_token",
        "raw-prompt",
        "secret_value_do_not_leak",
        "ignore previous instructions",
        "raw_prompt",
    ):
        assert unsafe not in serialized


