def test_search_and_relevant_memory_scrub_legacy_github_actions_org_runner_labels_raw_public_fields(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    init_memory_tree()
    raw_source_id = "https://api.github.com/orgs/capy/actions/runners/101/labels"
    dirty_raw_route = raw_source_id + "?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt"
    now = "2024-01-01T00:00:00+00:00"
    with sqlite3.connect(memory_tree_db_path()) as conn:
        conn.execute(
            """
            INSERT INTO sources (
                source_id, source_type, display_name, origin_uri, origin_kind,
                space_id, freshness_status, last_ingested_at, created_at, updated_at
            ) VALUES (?, 'auto_fetched_source', ?, ?, 'auto_fetch', 'legacy-org-runner-labels-space',
                'ok', ?, ?, ?)
            """,
            (raw_source_id, dirty_raw_route, raw_source_id, now, now, now),
        )
        conn.execute(
            """
            INSERT INTO chunks (
                chunk_id, source_id, source_ref, content_path, summary, approx_tokens,
                lifecycle_status, redaction_status, created_at, updated_at
            ) VALUES ('legacy-org-runner-labels-public-hit-chunk', ?, ?, '/tmp/metadata-only.md', ?, 20,
                'admitted', 'metadata_only', ?, ?)
            """,
            (
                raw_source_id,
                dirty_raw_route,
                "label count: 1; legacy raw org runner labels route " + dirty_raw_route,
                now,
                now,
            ),
        )

    search = search_memory("label count", limit=5)
