def test_github_actions_org_runners_route_and_final_url_matchers_accept_exact_route_and_reject_near_misses():
    exact = "https://api.github.com/orgs/capy/actions/runners"
    label = "github actions organization runners capy"

    assert capy_memory._github_actions_org_runners_route_path_matches(exact) is True
    assert capy_memory._github_actions_org_runners_path_matches(exact) is True
    assert capy_memory._github_actions_org_runners_path_org(exact) == "capy"
    assert capy_memory._safe_github_actions_org_runners_origin_text(label) == label
    assert capy_memory._github_actions_org_runners_fetch_origin_from_origin_text(label) == exact
    assert capy_memory._github_actions_org_runners_final_url_matches_origin(exact, exact) is True

    for near_miss in (
        "https://api.github.com.evil.test/orgs/capy/actions/runners",
        "https://ghp_SECRET_VALUE_DO_NOT_LEAK@api.github.com/orgs/capy/actions/runners",
        "https://api.github.com:444/orgs/capy/actions/runners",
        "https://API.GITHUB.COM/orgs/capy/actions/runners",
        "https://api.github.com/orgs/%20capy/actions/runners",
        "https://api.github.com/orgs//actions/runners",
        "https://api.github.com/orgs/other/actions/runners",
        "https://api.github.com/orgs/capy/actions/runners/extra",
        "https://api.github.com/orgs/capy/actions/runnersABC",
        "https://api.github.com/orgs/capy/actions/runners%2Fextra",
        "https://api.github.com/orgs/capy/actions/runners?access_token=SECRET_VALUE_DO_NOT_LEAK",
        "https://api.github.com/orgs/capy/actions/runners#raw-prompt",
    ):
        if near_miss in (
            "https://api.github.com/orgs/other/actions/runners",
            "https://api.github.com/orgs/capy/actions/runners?access_token=SECRET_VALUE_DO_NOT_LEAK",
            "https://api.github.com/orgs/capy/actions/runners#raw-prompt",
        ):
            assert capy_memory._github_actions_org_runners_path_matches(near_miss) is True
        assert capy_memory._github_actions_org_runners_final_url_matches_origin(exact, near_miss) is False

    assert capy_memory._github_actions_org_runners_final_url_matches_origin(exact, None) is False


