def test_search_and_relevant_memory_scrub_legacy_github_actions_org_runners_raw_public_fields(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    init_memory_tree()
    raw_source_id = "https://api.github.com/orgs/capy/actions/runners"
    route_derived_source_id = "https-api.github.com-orgs-capy-actions-runners"
    dashed_route_derived_source_id = "https:-api.github.com-orgs-capy-actions-runners"
    dirty_raw_route = raw_source_id + "?access_token=SECRET_VALUE_DO_NOT_LEAK#raw-prompt"
    now = "2024-01-01T00:00:00+00:00"
    with sqlite3.connect(memory_tree_db_path()) as conn:
        conn.execute(
            """
            INSERT INTO sources (
                source_id, source_type, display_name, origin_uri, origin_kind,
                space_id, freshness_status, last_ingested_at, created_at, updated_at
            ) VALUES (?, 'auto_fetched_source', ?, ?, 'auto_fetch', 'legacy-org-runners-space',
                'ok', ?, ?, ?)
            """,
            (raw_source_id, dirty_raw_route, raw_source_id, now, now, now),
        )
        conn.execute(
            """
            INSERT INTO chunks (
                chunk_id, source_id, source_ref, content_path, summary, approx_tokens,
                lifecycle_status, redaction_status, created_at, updated_at
            ) VALUES ('legacy-org-runners-public-hit-chunk', ?, ?, '/tmp/metadata-only.md', ?, 20,
                'admitted', 'metadata_only', ?, ?)
            """,
            (
                raw_source_id,
                dirty_raw_route,
                "runner count: 1; legacy raw org runners route " + dirty_raw_route,
                now,
                now,
            ),
        )

    search = search_memory("runner count", limit=5)
    relevant = relevant_memory_for_space("legacy-org-runners-space", limit=5)
    public_outputs = {"search": search, "relevant": relevant}
    serialized = json.dumps(public_outputs, sort_keys=True).lower()
    search_hit = search["results"][0]
    relevant_hit = relevant["results"][0]

    for hit in (search_hit, relevant_hit):
        assert hit["source_id"].startswith("github-actions-org-runners-")
        assert hit["source_id"] != raw_source_id
        assert hit["source_id"] != route_derived_source_id
        assert hit["source_id"] != dashed_route_derived_source_id
        assert hit["title"] == "GitHub Actions organization runners capy"
        assert hit["origin_uri"] == "github actions organization runners capy"
        assert hit["snippet"] == "github actions organization runners capy"

    assert "github actions organization runners capy" in serialized
    for unsafe in (
        raw_source_id.lower(),
        dirty_raw_route.lower(),
        "https://api.github.com",
        "/orgs/capy/actions/runners",
        route_derived_source_id,
        dashed_route_derived_source_id,
        "access_token",
        "raw-prompt",
        "secret_value_do_not_leak",
        "api_key",
        "raw_prompt",
    ):
        assert unsafe not in serialized


