def test_run_source_refresh_jobs_scrubs_legacy_github_actions_runner_groups_raw_source_id(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    raw_source_id = "https://api.github.com/repos/capy/spaces/actions/runner-groups"
    now = "2024-01-01T00:00:00+00:00"
    with sqlite3.connect(memory_tree_db_path()) as conn:
        conn.execute(
            """
            INSERT INTO sources (
                source_id, source_type, display_name, origin_uri, origin_kind,
                freshness_status, created_at, updated_at
            ) VALUES (?, 'source_registry', ?, 'github actions runner groups capy/spaces', 'auto_fetch', 'stale', ?, ?)
            """,
            (raw_source_id, raw_source_id, now, now),
        )
        conn.execute(
            """
            INSERT INTO jobs (job_id, kind, dedupe_key, payload_json, status, attempts, created_at, updated_at)
            VALUES ('legacy-runner-groups-job', 'source.refresh', ?, ?, 'pending', 0, ?, ?)
            """,
            (
                raw_source_id,
                json.dumps({"source_id": raw_source_id, "origin_uri": "github actions runner groups capy/spaces"}),
                now,
                now,
            ),
        )
    groups_body = json.dumps({
        "total_count": 1,
        "runner_groups": [{"id": 201, "name": "Default", "visibility": "all", "default": True}],
    }).encode("utf-8")
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def read(self, _limit=-1):
            return groups_body

    def fake_open(request, *, timeout):
        calls.append({"url": request.full_url, "accept": request.get_header("Accept"), "timeout": timeout})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_open)

    result = run_source_refresh_jobs(limit=1)
    search = search_memory("runner group count", limit=5)
    serialized = json.dumps({"result": result, "search": search}, sort_keys=True).lower()

    assert calls == [{"url": "https://api.github.com/repos/capy/spaces/actions/runner-groups", "accept": "application/json", "timeout": 8}]
