    assert result["jobs"][0]["source_id"].startswith("github-actions-runner-groups-")
    assert search["results"][0]["source_id"].startswith("github-actions-runner-groups-")
    assert search["results"][0]["origin_uri"] == "github actions runner groups capy/spaces"
    for unsafe in (
        raw_source_id.lower(),
        "api.github.com",
        "/repos/capy/spaces/actions/runner-groups",
    ):
        assert unsafe not in serialized


