    serialized = json.dumps({"search": search, "relevant": relevant}, sort_keys=True).lower()

    assert search["results"][0]["title"] == "GitHub Actions runner group repositories capy group 201"
    assert search["results"][0]["origin_uri"] == label
    assert search["results"][0]["snippet"] == label
    assert relevant["results"][0]["title"] == "GitHub Actions runner group repositories capy group 201"
    assert relevant["results"][0]["origin_uri"] == label
    assert relevant["results"][0]["snippet"] == label
    for unsafe in (
        "https://api.github.com",
        "/orgs/capy/actions/runner-groups/201/repositories",
        "access_token",
        "secret_value_do_not_leak",
        "raw-prompt",
        "renderer",
        '\"source\"',
        '\"html\"',
        '\"data\"',
        '\"body\"',
        "<script",
        "render()",
    ):
        assert unsafe not in serialized


