    assert capy_memory._github_actions_runner_group_repositories_final_url_matches_origin(exact, exact) is True
    assert capy_memory._github_actions_runner_group_repositories_final_url_matches_origin(exact, final_url) is False

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def geturl(self):
            return final_url

        def read(self, _limit=-1):
            read_calls.append(_limit)
            return hostile_body

    def fake_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.get_header("Accept")})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_open)

