def test_github_actions_org_runner_groups_route_matcher_public_label_round_trip_and_adjacent_non_stealing():
    exact = "https://api.github.com/orgs/capy/actions/runner-groups"
    label = "github actions organization runner groups capy"

    assert capy_memory._github_actions_org_runner_groups_route_path_matches(exact) is True
    assert capy_memory._github_actions_org_runner_groups_path_matches(exact) is True
    assert capy_memory._github_actions_org_runner_groups_path_org(exact) == "capy"
    assert capy_memory._safe_github_actions_org_runner_groups_origin_text(label) == label
    assert capy_memory._github_actions_org_runner_groups_fetch_origin_from_origin_text(label) == exact
    assert capy_memory._github_actions_org_runner_groups_canonical_display_name(label) == "GitHub Actions organization runner groups capy"

    adjacent_routes = (
        "https://api.github.com/orgs/capy/actions/runners",
        "https://api.github.com/orgs/capy/actions/runners/downloads",
        "https://api.github.com/orgs/capy/actions/runner-groups/201/repositories",
        "https://api.github.com/orgs/capy/actions/runner-groups/201/runners",
        "https://api.github.com/repos/capy/spaces/actions/runner-groups",
        "https://api.github.com/repos/capy/spaces/actions/runner-groups/201",
        "https://api.github.com/repos/capy/spaces/actions/runner-groups/201/runners",
    )
    for adjacent in adjacent_routes:
        assert capy_memory._github_actions_org_runner_groups_route_path_matches(adjacent) is False
        assert capy_memory._github_actions_org_runner_groups_path_matches(adjacent) is False

    unsupported_subroutes = (
        "https://api.github.com/orgs/capy/actions/runner-groups/201/runnersABC",
        "https://api.github.com/orgs/capy/actions/runner-groups/201",
        "https://api.github.com/orgs/capy/actions/runner-groups/201/repositories/extra",
        "https://api.github.com/orgs/capy/actions/runner-groups%2Fextra",
    )
    for unsupported in unsupported_subroutes:
        assert capy_memory._github_actions_org_runner_groups_unsupported_subroute_path_matches(unsupported) is True

    for supported in (
        "https://api.github.com/orgs/capy/actions/runner-groups",
        "https://api.github.com/orgs/capy/actions/runner-groups/201/repositories",
        "https://api.github.com/orgs/capy/actions/runner-groups/201/runners",
        "https://api.github.com/orgs/capy/actions/runners",
        "https://api.github.com/orgs/capy/actions/runners/downloads",
        "https://api.github.com/repos/capy/spaces/actions/runner-groups/201/runners",
    ):
        assert capy_memory._github_actions_org_runner_groups_unsupported_subroute_path_matches(supported) is False

    for near_miss in (
        "https://api.github.com.evil.test/orgs/capy/actions/runner-groups",
        "https://API.GITHUB.COM/orgs/capy/actions/runner-groups",
        "http://api.github.com/orgs/capy/actions/runner-groups",
        "https://api.github.com:444/orgs/capy/actions/runner-groups",
        "https://ghp_SECRET_VALUE_DO_NOT_LEAK@api.github.com/orgs/capy/actions/runner-groups",
        "https://api.github.com/orgs/%20capy/actions/runner-groups",
        "https://api.github.com/orgs/capy/actions/runner-groups/extra",
        "https://api.github.com/orgs/capy/actions/runner-groups%2Fextra",
        "https://api.github.com/orgs/capy/actions/runner-groupsABC",
    ):
        assert capy_memory._github_actions_org_runner_groups_path_matches(near_miss) is False
        assert capy_memory._github_actions_org_runner_groups_path_org(near_miss) == ""


def test_run_source_refresh_jobs_default_fetcher_ingests_github_actions_org_runner_groups_metadata_only_and_scrubs_public_outputs(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    receipt = register_source_reference({
        "source_id": "github-actions-org-runner-groups-source-refresh",
        "title": "https://api.github.com/orgs/capy/actions/runner-groups SECRET_VALUE_DO_NOT_LEAK",
        "origin_uri": "https://api.github.com/orgs/capy/actions/runner-groups?access_token=***#raw-prompt",
    })
    body = json.dumps({
        "total_count": 2,
        "runner_groups": [
            {
                "id": 201,
                "name": "Default Build.Group_1",
                "visibility": "all",
                "default": True,
                "allows_public_repositories": False,
                "inherited": False,
                "inherited_allows_public_repositories": True,
                "restricted_to_workflows": True,
                "selected_workflows": [".github/workflows/build.yml", "release.yml"],
                "workflow_restrictions_read_only": False,
                "runners_url": "https://api.github.com/orgs/capy/actions/runner-groups/201/runners",
                "selected_repositories_url": "https://api.github.com/orgs/capy/actions/runner-groups/201/repositories",
                "network_configuration_id": "net-1234",
            },
            {
                "id": 202,
                "name": "Private_Group-2",
                "visibility": "selected",
                "default": False,
                "allows_public_repositories": True,
                "inherited": True,
                "restricted_to_workflows": False,
                "selected_workflows": [],
            },
        ],
    }).encode("utf-8")
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def read(self, _limit=-1):
            return body

    def fake_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.get_header("Accept")})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_open)
    with sqlite3.connect(memory_tree_db_path()) as conn:
        queued_payload = conn.execute("SELECT payload_json FROM jobs WHERE job_id = ?", (receipt["job_id"],)).fetchone()[0].lower()
    public_before = json.dumps({"receipt": receipt, "catalog": source_catalog(limit=5), "jobs": list_source_refresh_jobs(limit=5)}, sort_keys=True).lower()

    assert receipt["origin_uri"] == "github actions organization runner groups capy"
    assert "github actions organization runner groups capy" in queued_payload
    for unsafe in ("https://api.github.com", "/orgs/capy/actions/runner-groups", "access_token", "raw-prompt", "secret_value_do_not_leak", "raw_prompt", "renderer", "<script"):
        assert unsafe not in queued_payload
        assert unsafe not in public_before

    result = run_source_refresh_jobs(limit=1)
    persisted = (root / "vault" / "github-actions-org-runner-groups-source-refresh.md").read_text(encoding="utf-8").lower()
    search = search_memory("runner group id: 202", limit=5)
    serialized = json.dumps({"result": result, "catalog": source_catalog(limit=5), "jobs": list_source_refresh_jobs(limit=5), "search": search}, sort_keys=True).lower()
    exact = "https://api.github.com/orgs/capy/actions/runner-groups"

    assert calls == [{"url": exact, "timeout": 8, "accept": "application/json"}]
    assert exact not in serialized
    assert result["processed"] == 1
    assert result["jobs"][0]["status"] == "completed"
    assert result["jobs"][0]["prompt_preflight"]["boundary"] == "auto_fetched_source"
    assert result["jobs"][0]["prompt_preflight"]["raw_prompt_stored"] is False
    assert search["results"][0]["source_id"] == "github-actions-org-runner-groups-source-refresh"
    assert search["results"][0]["origin_uri"] == "github actions organization runner groups capy"
    assert "github actions organization runner groups for capy" in persisted
    assert "runner group count: 2" in persisted
    assert "runner group id: 201" in persisted
    assert "name: default build.group_1" in persisted
    assert "visibility: all" in persisted
    assert "default: true" in persisted
    assert "allows public repositories: false" in persisted
    assert "inherited allows public repositories: true" in persisted
    assert "restricted to workflows: true" in persisted
    assert "selected workflows: .github/workflows/build.yml, release.yml" in persisted
    assert "workflow restrictions read only: false" in persisted
    assert "runner group id: 202" in persisted
    for unsafe in (
        "secret_value_do_not_leak", "api.github.com", "https://", "/orgs/capy/actions/runner-groups",
        "access_token", "raw-prompt", "ignore previous instructions", "api_key", "token", "credential", "renderer",
        "<script", "render()", "runners_url", "selected_repositories_url", "network_configuration_id", "html_url", '"source"', '"data"', "body"
    ):
        assert unsafe not in serialized
        assert unsafe not in persisted


