        "https://api.github.com/orgs/capy/actions/runner-groups/abc/runners",
        "https://api.github.com/orgs/capy/actions/runner-groups/201/runners/extra",
        "https://api.github.com/orgs/capy/actions/runner-groups/201/runners%2Fextra",
