def test_run_source_refresh_jobs_default_fetcher_ingests_github_actions_runner_group_metadata_only(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    receipt = register_source_reference({
        "source_id": "github-actions-runner-group-source-refresh",
        "title": "https://api.github.com/repos/capy/spaces/actions/runner-groups/201 SECRET_VALUE_DO_NOT_LEAK",
        "origin_uri": "https://api.github.com/repos/capy/spaces/actions/runner-groups/201?access_token=***#raw-prompt",
    })
    group_body = json.dumps({
        "id": 201,
        "name": "Default Build.Group_1",
        "visibility": "all",
        "default": True,
        "allows_public_repositories": False,
        "inherited": False,
        "inherited_allows_public_repositories": True,
        "restricted_to_workflows": True,
        "selected_workflows": [".github/workflows/build.yml", "release.yml", "octo-org/octo-repo/.github/workflows/deploy.yaml@refs/heads/main"],
        "workflow_restrictions_read_only": False,
        "runners_url": "https://api.github.com/repos/capy/spaces/actions/runner-groups/201/runners",
        "hosted_runners_url": "https://api.github.com/repos/capy/spaces/actions/runner-groups/201/hosted-runners",
        "selected_repositories_url": "https://api.github.com/repos/capy/spaces/actions/runner-groups/201/repositories",
        "network_configuration_id": "net-1234",
    }).encode("utf-8")
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def read(self, _limit=-1):
            return group_body

    def fake_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.get_header("Accept")})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_open)
    with sqlite3.connect(memory_tree_db_path()) as conn:
        queued_payload = conn.execute(
            "SELECT payload_json FROM jobs WHERE job_id = ?",
            (receipt["job_id"],),
        ).fetchone()[0].lower()
    assert receipt["origin_uri"] == "github actions runner group capy/spaces group 201"
    assert "https://api.github.com" not in queued_payload
    assert "/repos/capy/spaces/actions/runner-groups/201" not in queued_payload
    assert "access_token" not in queued_payload
    assert "raw-prompt" not in queued_payload

    result = run_source_refresh_jobs(limit=1)
    persisted = (root / "vault" / "github-actions-runner-group-source-refresh.md").read_text(encoding="utf-8").lower()
    search = search_memory("runner group id: 201", limit=5)
    catalog = capy_memory.source_catalog(limit=10)
    serialized = json.dumps({"receipt": receipt, "result": result, "search": search, "jobs": list_source_refresh_jobs(limit=5), "catalog": catalog}, sort_keys=True).lower()

    assert calls == [{
        "url": "https://api.github.com/repos/capy/spaces/actions/runner-groups/201",
        "timeout": 8,
        "accept": "application/json",
    }]
    assert result["processed"] == 1
    assert result["jobs"][0]["job_id"] == receipt["job_id"]
    assert result["jobs"][0]["status"] == "completed"
    assert result["jobs"][0]["prompt_preflight"]["boundary"] == "auto_fetched_source"
    assert result["jobs"][0]["prompt_preflight"]["raw_prompt_stored"] is False
    assert search["results"][0]["source_id"] == "github-actions-runner-group-source-refresh"
    assert "github actions runner group for capy/spaces group 201" in persisted
    assert "runner group id: 201" in persisted
    assert "name: default build.group_1" in persisted
    assert "visibility: all" in persisted
    assert "default: true" in persisted
    assert "allows public repositories: false" in persisted
    assert "inherited: false" in persisted
    assert "inherited allows public repositories: true" in persisted
    assert "restricted to workflows: true" in persisted
    assert "selected workflows: .github/workflows/build.yml, release.yml, octo-org/octo-repo/.github/workflows/deploy.yaml@refs/heads/main" in persisted
    assert "workflow restrictions read only: false" in persisted
    catalog_sources = [
        source
        for connector in catalog["connectors"]
        for source in connector["sources"]
        if source["source_id"] == "github-actions-runner-group-source-refresh"
    ]
    assert catalog_sources
    assert catalog_sources[0]["origin_uri"] == "github actions runner group capy/spaces group 201"
    assert catalog_sources[0]["display_name"] == "GitHub Actions runner group capy/spaces group 201"
    for unsafe in (
        "secret_value_do_not_leak",
        "api.github.com",
        "https://",
        "access_token",
        "raw-prompt",
        "ignore previous instructions",
        "api_key",
        "renderer",
        "<script",
        "render()",
        "url",
        "html_url",
    ):
        assert unsafe not in serialized
        assert unsafe not in persisted
    assert '\"source\"' not in serialized
    assert "\nsource:" not in persisted


