def test_github_actions_runner_downloads_route_matcher_recognizes_exact_route_and_rejects_near_misses():
    exact = "https://api.github.com/repos/capy/spaces/actions/runners/downloads"
    label = "github actions runner downloads capy/spaces"

    assert capy_memory._github_actions_runner_downloads_route_path_matches(exact) is True
    assert capy_memory._github_actions_runner_downloads_path_matches(exact) is True
    assert capy_memory._github_actions_runner_downloads_path_repo(exact) == "capy/spaces"
    assert capy_memory._safe_github_actions_runner_downloads_origin_text(label) == label
    assert capy_memory._github_actions_runner_downloads_fetch_origin_from_origin_text(label) == exact
    assert capy_memory._github_actions_runner_downloads_final_url_matches_origin(exact, exact) is True

    for near_miss in (
        "https://api.github.com.evil.test/repos/capy/spaces/actions/runners/downloads",
        "https://api.github.com/repos/capy/spaces/actions/runners/downloads/123",
        "https://api.github.com/repos/capy/spaces/actions/runners/downloadsABC",
        "https://api.github.com/repos/capy/spaces/actions/runners/downloads%2F123",
        "https://ghp_SECRET_VALUE_DO_NOT_LEAK@api.github.com/repos/capy/spaces/actions/runners/downloads",
        "https://api.github.com:444/repos/capy/spaces/actions/runners/downloads",
    ):
        assert capy_memory._github_actions_runner_downloads_path_matches(near_miss) is False
        assert capy_memory._github_actions_runner_downloads_path_repo(near_miss) == ""
        assert capy_memory._github_actions_runner_downloads_final_url_matches_origin(exact, near_miss) is False


