def test_run_source_refresh_jobs_default_fetcher_ingests_github_actions_runner_downloads_metadata_only(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    monkeypatch.setenv("CAPY_MEMORY_REFRESH_ALLOWED_HOSTS", "api.github.com")
    init_memory_tree()
    receipt = register_source_reference({
        "source_id": "github-actions-runner-downloads-source-refresh",
        "title": "GitHub Actions Runner Downloads Source Refresh",
        "origin_uri": "https://api.github.com/repos/capy/spaces/actions/runners/downloads?access_token=***#raw-prompt",
    })
    downloads_body = json.dumps([
        {
            "os": "osx",
            "architecture": "arm64",
            "download_url": "https://objects.githubusercontent.example/actions-runner-osx-arm64-2.317.0.tar.gz?token=SECRET_VALUE_DO_NOT_LEAK",
            "filename": "actions-runner-osx-arm64-2.317.0.tar.gz",
        },
        {
            "os": "linux",
            "architecture": "x64",
            "download_url": "https://objects.githubusercontent.example/actions-runner-linux-x64-2.317.0.tar.gz?token=SECRET_VALUE_DO_NOT_LEAK",
            "filename": "actions-runner-linux-x64-2.317.0.tar.gz",
        },
        {
            "os": "win",
            "architecture": "x64",
            "download_url": "https://objects.githubusercontent.example/actions-runner-win-x64-2.317.0.zip?token=SECRET_VALUE_DO_NOT_LEAK",
            "filename": "actions-runner-win-x64-2.317.0.zip",
        },
    ]).encode("utf-8")
    calls = []

    class FakeResponse:
        headers = {"Content-Type": "application/json; charset=utf-8"}

        def __enter__(self):
            return self

        def __exit__(self, *_exc):
            return False

        def read(self, _limit=-1):
            return downloads_body

    def fake_open(request, *, timeout):
        calls.append({"url": request.full_url, "timeout": timeout, "accept": request.get_header("Accept")})
        return FakeResponse()

    monkeypatch.setattr(capy_memory, "_refresh_open", fake_open)
    with sqlite3.connect(memory_tree_db_path()) as conn:
        queued_payload = conn.execute(
            "SELECT payload_json FROM jobs WHERE job_id = ?",
            (receipt["job_id"],),
        ).fetchone()[0].lower()
    assert "https://api.github.com" not in queued_payload
    assert "/repos/capy/spaces/actions/runners/downloads" not in queued_payload
    assert "access_token" not in queued_payload
    assert "raw-prompt" not in queued_payload

    result = run_source_refresh_jobs(limit=1)
    persisted = (root / "vault" / "github-actions-runner-downloads-source-refresh.md").read_text(encoding="utf-8").lower()
    search = search_memory("actions-runner-linux-x64-2.317.0.tar.gz", limit=5)
    serialized = json.dumps({"result": result, "search": search}, sort_keys=True).lower()

    assert calls == [{
        "url": "https://api.github.com/repos/capy/spaces/actions/runners/downloads",
        "timeout": 8,
        "accept": "application/json",
    }]
    assert result["processed"] == 1
    assert result["jobs"][0]["job_id"] == receipt["job_id"]
    assert result["jobs"][0]["status"] == "completed"
    assert result["jobs"][0]["prompt_preflight"]["boundary"] == "auto_fetched_source"
    assert result["jobs"][0]["prompt_preflight"]["raw_prompt_stored"] is False
    assert search["results"][0]["source_id"] == "github-actions-runner-downloads-source-refresh"
    assert "github actions runner downloads for capy/spaces" in persisted
    assert "runner download count: 3" in persisted
    assert "os: osx" in persisted
    assert "architecture: arm64" in persisted
    assert "filename: actions-runner-osx-arm64-2.317.0.tar.gz" in persisted
    assert "os: linux" in persisted
    assert "filename: actions-runner-linux-x64-2.317.0.tar.gz" in persisted
    assert "filename: actions-runner-win-x64-2.317.0.zip" in persisted
    for unsafe in (
        "secret_value_do_not_leak",
        "download_url",
        "objects.githubusercontent.example",
        "access_token",
        "raw-prompt",
        "html_url",
        "https://api.github.com",
        "/repos/capy/spaces/actions/runners/downloads",
        "?token",
    ):
        assert unsafe not in serialized
        assert unsafe not in persisted


