@pytest.mark.parametrize("raw_name_field", ["title", "display_name"])
@pytest.mark.parametrize("raw_name_kind", ["raw-url", "safe-marker"])
def test_source_catalog_canonicalizes_github_actions_org_runner_downloads_raw_display_name(
    tmp_path, monkeypatch, raw_name_field, raw_name_kind
):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
    init_memory_tree()
    raw_url = "https://api.github.com/orgs/capy/actions/runners/downloads?access_token=***#raw-prompt"
    custom_marker = "CUSTOM RAW DISPLAY LEAK MARKER"
    raw_display_name = raw_url if raw_name_kind == "raw-url" else custom_marker

    receipt = register_source_reference({
        "source_id": f"github-actions-org-runner-downloads-{raw_name_field}-{raw_name_kind}",
        raw_name_field: raw_display_name,
        "origin_uri": raw_url,
    })

    assert receipt["origin_uri"] == "github actions organization runner downloads capy"
    with sqlite3.connect(memory_tree_db_path()) as conn:
        stored_display_name = conn.execute(
            "SELECT display_name FROM sources WHERE source_id = ?",
            (receipt["source_id"],),
        ).fetchone()[0]
        conn.execute(
            "UPDATE sources SET display_name = ? WHERE source_id = ?",
            (custom_marker, receipt["source_id"]),
        )
    assert stored_display_name == "GitHub Actions organization runner downloads capy"

    catalog = source_catalog(limit=5)
    jobs = list_source_refresh_jobs(limit=5)
    auto_fetch_connector = next(
        connector for connector in catalog["connectors"] if connector["connector_id"] == "auto_fetch"
    )
    source = auto_fetch_connector["sources"][0]

    assert source["origin_uri"] == "github actions organization runner downloads capy"
    assert source["display_name"] == "GitHub Actions organization runner downloads capy"

    public_serialized = json.dumps({"catalog": catalog, "jobs": jobs}, sort_keys=True).lower()
    serialized = json.dumps({"catalog": catalog, "jobs": jobs, "receipt": receipt}, sort_keys=True).lower()
    assert custom_marker.lower() not in public_serialized
    assert "https://api.github.com" not in public_serialized
    assert "/orgs/capy/actions/runners/downloads" not in public_serialized
    assert "access_token" not in public_serialized
    assert "raw-prompt" not in public_serialized
    assert "https://api.github.com" not in serialized
    assert "/orgs/capy/actions/runners/downloads" not in serialized


